import type { Drill } from "./types";

// Student / early drills, keyed by module slug — 25 per module.
// Persona: a high school student — class discussions, presentations, essays and
// college applications, emails to teachers and counselors, clubs and teams,
// group projects, and first jobs. Merged into course.ts.
export const STUDENT_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-stu-early-01","level":"early","profession":"student","title":"The extension email that hides the ask","scenario":"Your history essay is due tomorrow and you need two more days because a family commitment ate your weekend. Your draft email to your teacher spends three paragraphs explaining the weekend before the request appears.","task":"Write a 2-3 sentence email that puts the extension request in the first sentence.","tips":["Sentence one: what you're asking for and the new date you propose.","One sentence of reason is enough — it's context, not the point.","End with a line that makes it easy to say yes or no."],"focus":["clarity","structure"],"placeholder":"Could I have until Thursday to submit the history essay?"},
    {"id":"lead-stu-early-02","level":"early","profession":"student","title":"The group chat update that rambles","scenario":"You finished your slides for the group presentation and uploaded them to the shared folder. Your draft message to the group chat narrates your whole evening before mentioning the slides are done.","task":"Write a 1-2 sentence group chat message that leads with the news.","tips":["First words: slides are done and uploaded.","Say where to find them and what you need from others, if anything.","Skip the story of how long it took."],"focus":["concision","clarity"]},
    {"id":"lead-stu-early-03","level":"early","profession":"student","title":"The recommendation letter ask","scenario":"You need a recommendation letter from your counselor for a summer program, due in three weeks. Your draft email opens with two paragraphs about how much the program means to you before the actual request.","task":"Write an email opening (2-3 sentences) that states the request and the deadline first.","tips":["Lead with the ask: a recommendation letter, for what, due when.","Why you're excited is support — one sentence, after the ask.","Offer to send your resume or activity list to make it easy."],"focus":["clarity","structure"],"placeholder":"Would you be willing to write me a recommendation letter for the state science program? It's due March 21."},
    {"id":"lead-stu-early-04","level":"early","profession":"student","title":"The regrade request buried in worry","scenario":"You think question 4 on your chemistry test was marked wrong — your answer matches the posted key. Your draft email to the teacher opens with apologies about bothering them and worries about your grade before naming the issue.","task":"Write a 2-3 sentence email that names the specific question and issue in sentence one.","tips":["Lead with the specific claim: question 4, marked wrong, matches the key.","Drop the apologetic warm-up — a clear question is not a bother.","Ask for one specific action: a second look."],"focus":["clarity","precision"],"placeholder":"Could you take a second look at question 4 on my test? My answer matches the posted key."},
    {"id":"lead-stu-early-05","level":"early","profession":"student","title":"The meeting-change announcement","scenario":"You run the photography club and this week's meeting has to move from Wednesday to Thursday in a different room. Your draft announcement opens with a recap of last week's meeting before mentioning the change.","task":"Write an announcement whose first sentence carries the new day, time, and room.","tips":["The change IS the message — put it first.","People skim announcements; assume they read one line.","Recap of last week can go last or go away."],"focus":["clarity","concision"],"placeholder":"Photography club is moving to Thursday at 3:30 in Room 118 this week."},
    {"id":"lead-stu-early-06","level":"early","profession":"student","title":"The shift-swap text","scenario":"You work weekends at a grocery store and need someone to cover your Saturday shift because of the SAT. Your draft text to a coworker explains the whole test situation before asking.","task":"Write a 1-2 sentence text that leads with the swap request and the date.","tips":["Ask first: can you cover Saturday, and which hours.","Offer the trade in the same breath — what you'll cover in return.","One line of reason is plenty."],"focus":["clarity","concision"]},
    {"id":"lead-stu-early-07","level":"early","profession":"student","title":"Telling coach you'll miss practice","scenario":"You have to miss Thursday's soccer practice for a required academic awards ceremony. Your draft message to your coach buries that fact under a long apology and a promise that you take the team seriously.","task":"Write a 2-3 sentence message that states the absence and reason up front.","tips":["Lead with the fact: missing Thursday, and why in the same sentence.","Say how you'll make it up — that beats promising you care.","Coaches respect direct more than sorry."],"focus":["clarity","impact"]},
    {"id":"lead-stu-early-08","level":"early","profession":"student","title":"The presentation that starts with the point","scenario":"You're opening a five-minute English presentation arguing that the novel's narrator is unreliable. Your draft opening summarizes the plot for a full minute before your argument appears.","task":"Write the first two sentences of the presentation, leading with your thesis.","tips":["State the claim in sentence one — the class knows the plot already.","Preview your evidence in sentence two.","A strong open earns attention for the rest."],"focus":["structure","impact"],"placeholder":"The narrator lies to us three times in the first chapter — and that changes how we should read everything after."},
    {"id":"lead-stu-early-09","level":"early","profession":"student","title":"The homework question that takes forever","scenario":"You're emailing your math teacher because problem 12 seems to contradict what was taught in class. Your draft spends a paragraph on how you usually understand the material before the question shows up.","task":"Rewrite the email so the question is the first sentence.","tips":["Ask the question first, in one sentence.","Then give the minimum context: what you tried, where it broke.","Teachers answer clear questions faster."],"focus":["clarity","concision"],"placeholder":"On problem 12, should we use the formula from Tuesday, or does the negative exponent change it?"},
    {"id":"lead-stu-early-10","level":"early","profession":"student","title":"The student council proposal","scenario":"You're proposing a water-bottle refill station near the gym at the next student council meeting. Your draft speech opens with general remarks about school improvement before the actual proposal.","task":"Write a 2-3 sentence proposal opening that names the ask in sentence one.","tips":["Sentence one: what you propose and roughly what it costs.","Then the single strongest reason.","Cut the throat-clearing about improvement in general."],"focus":["clarity","structure"]},
    {"id":"lead-stu-early-11","level":"early","profession":"student","title":"Joining a club mid-year","scenario":"You want to join the debate team even though the season already started. Your draft email to the club advisor tells your whole story with public speaking before asking whether joining now is possible.","task":"Write a 2-3 sentence email that leads with the ask.","tips":["First sentence: can I join now, and what's the next step.","One sentence on why you'd add value.","Make the reply easy: a yes, a no, or a meeting time."],"focus":["clarity","concision"]},
    {"id":"lead-stu-early-12","level":"early","profession":"student","title":"The newspaper pitch","scenario":"You write for the school paper and want to pitch a story about the cafeteria switching to a new vendor. Your draft message to the editor describes your reporting process before stating the story idea.","task":"Write a 1-2 sentence pitch that leads with the story.","tips":["Headline first: what the story is and why readers care.","Your process is support — mention it only if asked.","Editors decide in one line; give them that line."],"focus":["impact","concision"],"placeholder":"Pitch: the cafeteria is switching vendors in March, and prices are changing —"},
    {"id":"lead-stu-early-13","level":"early","profession":"student","title":"Reporting the broken microscope","scenario":"During biology lab you noticed the microscope at your station has a cracked lens that could scratch slides. Your draft note to the teacher walks through your whole lab session before mentioning the damage.","task":"Write a 1-2 sentence note that leads with what's broken and the risk.","tips":["First words: which equipment, what's wrong, what could happen.","How you noticed is optional detail.","Report it like a headline, not a diary entry."],"focus":["clarity","precision"]},
    {"id":"lead-stu-early-14","level":"early","profession":"student","title":"The fundraiser total, eventually","scenario":"Your club's bake sale raised $412, beating the $300 goal. Your draft update to the club advisor recounts the whole day — setup, weather, who helped — before the total appears in the last line.","task":"Write a 2-3 sentence update that leads with the number.","tips":["The total is the headline — first sentence.","Compare it to the goal so the number means something.","One highlight from the day is enough color."],"focus":["clarity","impact"],"placeholder":"The bake sale raised $412 — $112 over our goal."},
    {"id":"lead-stu-early-15","level":"early","profession":"student","title":"Asking for the missing section","scenario":"Your group's project is due Monday, and you still need one member's research section by Friday to have time to combine everything. Your draft message softens the ask with so many maybes that the deadline never lands.","task":"Write a 1-2 sentence message that leads with what you need and by when.","tips":["Lead with the ask: your section, by Friday.","Say why in one clause: to merge everything before Monday.","Friendly and clear beat vague and polite."],"focus":["clarity","impact"],"placeholder":"Can you send your research section by Friday?"},
    {"id":"lead-stu-early-16","level":"early","profession":"student","title":"The question for the admissions office","scenario":"You're emailing a college admissions office to ask whether they accept a fourth recommendation letter. Your draft opens with two paragraphs introducing yourself and your interest in the school before asking.","task":"Write a 2-3 sentence email that puts the question first.","tips":["Ask the question in sentence one.","One sentence identifying yourself (name, applicant year) is enough.","Admissions offices answer hundreds of emails — reward the skimmer."],"focus":["concision","clarity"]},
    {"id":"lead-stu-early-17","level":"early","profession":"student","title":"The study-group SOS","scenario":"The biology test is Friday and you missed Tuesday's class covering cell respiration. You need someone's notes tonight. Your draft group-chat message starts with a long explanation of why you were absent.","task":"Write a 1-2 sentence message that leads with the specific ask.","tips":["Lead with what you need: Tuesday's notes, tonight.","Name the topic so people know if they can help.","The absence story can wait for lunch."],"focus":["clarity","concision"],"placeholder":"Can anyone send Tuesday's notes on cell respiration tonight?"},
    {"id":"lead-stu-early-18","level":"early","profession":"student","title":"Canceling on your debate partner","scenario":"You can't make tomorrow's practice round with your debate partner because of a dentist appointment. Your draft text apologizes three ways before saying you can't come — and never proposes another time.","task":"Write a 2-sentence text that leads with the cancellation and offers an alternative.","tips":["Sentence one: can't make tomorrow, here's why in a word.","Sentence two: two alternative times you CAN do.","An alternative shows respect better than a third apology."],"focus":["clarity","impact"]},
    {"id":"lead-stu-early-19","level":"early","profession":"student","title":"Following up on the job application","scenario":"You applied to a smoothie shop ten days ago and haven't heard back. You're writing a short follow-up email to the manager, but your draft buries the purpose under small talk about loving the shop.","task":"Write a 2-3 sentence follow-up that states its purpose in sentence one.","tips":["Lead with it: following up on my application from June 20.","Restate your availability in one sentence — that's what managers check.","Keep the enthusiasm to one clause, not a paragraph."],"focus":["clarity","concision"]},
    {"id":"lead-stu-early-20","level":"early","profession":"student","title":"The partner problem, stated plainly","scenario":"Your project partner hasn't contributed anything with five days left, and you need your teacher's guidance now — more time, or a way to split the grade. Your draft email vents about the partner for two paragraphs before any request appears.","task":"Write a 2-3 sentence email that leads with what you need from the teacher.","tips":["Lead with the ask: guidance on how to proceed, given the situation.","State the facts in one neutral sentence — no character attacks.","Asking early looks responsible; venting looks like blame."],"focus":["clarity","structure"],"placeholder":"I need your advice on the group project: with five days left, my partner hasn't been able to contribute yet."},
    {"id":"lead-stu-early-21","level":"early","profession":"student","title":"The yearbook photo deadline","scenario":"You're on yearbook staff, and every club needs to submit its group photo by next Friday or it won't make the book. Your draft email to club presidents explains the printing process before stating the deadline.","task":"Write an email opening (1-2 sentences) that leads with the deadline and the consequence.","tips":["First sentence: submit by next Friday or the photo won't be printed.","The consequence is what makes people act — don't hide it.","Printing logistics belong at the bottom, if anywhere."],"focus":["impact","clarity"]},
    {"id":"lead-stu-early-22","level":"early","profession":"student","title":"Missing the field trip","scenario":"You have to skip the museum field trip because it conflicts with a make-up exam. Your teacher needs to adjust the headcount and the worksheet plan. Your draft message tells the story of the scheduling conflict from the beginning.","task":"Write a 1-2 sentence message that leads with the fact your teacher needs.","tips":["Lead with: not coming on the trip, taking the make-up exam instead.","Ask what to do about the assignment in the same message.","The scheduling saga adds nothing — cut it."],"focus":["clarity","concision"],"placeholder":"I won't be on Friday's museum trip — it conflicts with my make-up exam."},
    {"id":"lead-stu-early-23","level":"early","profession":"student","title":"The venue fell through","scenario":"The community room your club booked for its movie night just canceled on you. The event is in nine days. Your message to the club officers starts with how frustrated you are before sharing the news or a plan.","task":"Write a 2-3 sentence message that leads with the news and one next step.","tips":["Headline first: venue canceled, event is in nine days.","Follow with one concrete next step, not a mood.","People rally around a plan, not a complaint."],"focus":["clarity","impact"]},
    {"id":"lead-stu-early-24","level":"early","profession":"student","title":"The volunteer-hours letter","scenario":"You need the coordinator at the animal shelter to sign a letter confirming your 40 volunteer hours for your application, due next Wednesday. Your draft email reminisces about your favorite shifts before making the request.","task":"Write a 2-3 sentence email that leads with the request and deadline.","tips":["Lead with the ask: a signed hours letter by next Wednesday.","Attach or offer the form in the same breath.","One warm sentence at the end beats three at the start."],"focus":["clarity","structure"]},
    {"id":"lead-stu-early-25","level":"early","profession":"student","title":"The yes that takes three paragraphs","scenario":"Your teacher emailed one question: can you present your project on Monday instead of Wednesday? The answer is yes. Your draft reply explains your whole week's schedule before ever saying so.","task":"Write a reply that answers in the first word or two, then adds one detail if needed.","tips":["Answer the yes/no question first — literally first.","One caveat or logistic can follow the answer.","Don't make a teacher hunt for a one-word answer."],"focus":["concision","clarity"],"placeholder":"Yes — Monday works."}
  ],
  "start-with-the-audience": [
    {"id":"audience-stu-early-01","level":"early","profession":"student","title":"The robotics pitch to the principal","scenario":"Your robotics club needs $600 from the school budget for competition parts. Your draft to the principal is full of motor specs and controller model numbers. The principal cares about student learning, school reputation, and cost.","task":"Rewrite the pitch in 3-4 sentences framed around what the principal cares about.","tips":["Translate parts into outcomes: how many students, what they learn, what the school gets.","Name the cost once, plainly, next to what it buys.","Save the model numbers for the order form."],"focus":["audience","impact"],"placeholder":"For $600, twelve students get to build and compete at regionals —"},
    {"id":"audience-stu-early-02","level":"early","profession":"student","title":"Recruiting freshmen who've never heard of you","scenario":"You're writing the club-fair flyer for Model UN. Your draft leads with committee names, position papers, and parliamentary procedure — terms that mean nothing to a ninth grader deciding where to spend Thursday afternoons.","task":"Write a 2-3 sentence pitch a freshman would actually understand and want.","tips":["Lead with what they'd DO and feel, not the program's vocabulary.","One concrete moment (debating as France, winning a gavel) beats a list of terms.","Answer their real question: will I like this and will I have friends here?"],"focus":["audience","impact"]},
    {"id":"audience-stu-early-03","level":"early","profession":"student","title":"Catching up the classmate who missed lab","scenario":"Your lab partner missed today's chemistry class and texts you asking what they missed. You're tempted to forward your raw notes. What they actually need: what happened, what's due, and what to do before Thursday's lab.","task":"Write a 3-4 sentence catch-up message organized around what they need to do.","tips":["Lead with the action items: what's due and by when.","Summarize the lesson in one sentence, not a transcript.","Point them to the notes for depth instead of pasting everything."],"focus":["audience","structure"],"placeholder":"Two things before Thursday: finish the pre-lab sheet and read 6.2."},
    {"id":"audience-stu-early-04","level":"early","profession":"student","title":"The essay full of school shorthand","scenario":"Your college application essay mentions 'Link Crew,' 'the 200 hall,' and 'Mr. D's third-period debates' — shorthand every kid at your school knows. An admissions reader in another state has no idea what any of it means.","task":"Rewrite one of those references (2-3 sentences) so a stranger understands it instantly.","tips":["Assume the reader knows nothing about your school.","Replace names with what the thing IS: a mentoring program, a hallway, a class tradition.","Keep the personal detail; translate the label."],"focus":["audience","clarity"]},
    {"id":"audience-stu-early-05","level":"early","profession":"student","title":"Explaining your code project to an English teacher","scenario":"Your science-fair judge this round is an English teacher. Your project is an app that predicts bus delays using historical data. Your prepared spiel is full of 'training data,' 'regression,' and 'API calls.'","task":"Explain the project in 2-3 sentences a non-technical judge will follow and remember.","tips":["Lead with the problem it solves — everyone has waited for a late bus.","Replace method jargon with what the app does in plain verbs.","Give one concrete result: how close its predictions come."],"focus":["audience","clarity"],"placeholder":"My app tells you how late your school bus will actually be —"},
    {"id":"audience-stu-early-06","level":"early","profession":"student","title":"The note for the substitute","scenario":"Your teacher asked you, as class rep, to leave a note telling tomorrow's substitute where the class is in the unit. Your draft is written like a note to a classmate — full of 'the usual warm-up' and 'the packet from before break.'","task":"Write a 3-4 sentence note a stranger could run the class from.","tips":["The sub knows nothing: name the unit, the page, the routine explicitly.","Spell out 'the usual' — it isn't usual to them.","Put what to do first, background second."],"focus":["audience","clarity"]},
    {"id":"audience-stu-early-07","level":"early","profession":"student","title":"The cover letter that speaks retail","scenario":"You're applying to a part-time job at a bookstore. Your draft cover email lists your GPA, your AP classes, and your science-fair medal. The manager is wondering: will this kid show up on time, work the register, and be good with customers?","task":"Rewrite the email body (3-4 sentences) around what the manager actually needs to know.","tips":["Translate school experience into job behaviors: reliability, teamwork, handling people.","Your availability is a headline fact for a manager, not a footnote.","One school achievement is plenty, framed as evidence you follow through."],"focus":["audience","impact"]},
    {"id":"audience-stu-early-08","level":"early","profession":"student","title":"Tutoring without the textbook voice","scenario":"You tutor a seventh grader in algebra. Asked why you can't divide by zero, you start reciting the formal definition of division. The kid's eyes glaze. They need an explanation that connects to something they already know.","task":"Explain why dividing by zero doesn't work, in 2-3 sentences a 12-year-old would get.","tips":["Start from something they know: sharing things among people.","Use one concrete example with small numbers.","Check the altitude: no terms they haven't met yet."],"focus":["audience","clarity"]},
    {"id":"audience-stu-early-09","level":"early","profession":"student","title":"The play call for brand-new players","scenario":"You're a returning player explaining the team's basic zone defense to freshmen at their first basketball practice. Your draft explanation uses last season's nicknames for positions and assumes they know where to stand.","task":"Explain the zone in 3-4 sentences a first-day player can act on.","tips":["Anchor to what they can see: the paint, the wings, the ball.","One job per person — don't explain all five roles at once.","Skip the history of why the team runs it."],"focus":["audience","structure"]},
    {"id":"audience-stu-early-10","level":"early","profession":"student","title":"The budget ask, translated for council","scenario":"Your environmental club wants $150 from student council for garden supplies. Your draft is all about soil health and native species. Council members compare requests by one measure: how many students benefit per dollar.","task":"Rewrite the request in 2-3 sentences framed for how council actually decides.","tips":["Lead with reach: how many students the garden serves and how.","Put the dollar figure next to the benefit.","Keep one vivid detail; cut the botany lecture."],"focus":["audience","precision"],"placeholder":"$150 in supplies keeps the garden producing for all 30 club members plus the two classes that use it —"},
    {"id":"audience-stu-early-11","level":"early","profession":"student","title":"The schedule-change request to the front office","scenario":"You want to switch from fourth-period study hall into orchestra. Your draft email to the scheduling office explains your love of music at length. The office processes requests by rule: is there space, is there a conflict, is the form signed.","task":"Write a 2-3 sentence request that gives the office exactly what it needs to process it.","tips":["Lead with the specific change: drop X period 4, add Y period 4.","Confirm the checklist items they'll look for: form, signatures, no conflicts.","Save the passion for the orchestra director."],"focus":["audience","precision"]},
    {"id":"audience-stu-early-12","level":"early","profession":"student","title":"Homecoming, explained to an exchange student","scenario":"The exchange student in your grade asks what homecoming actually is. Your first attempt — 'it's like spirit week plus the game plus semi-formal' — explains one unknown with three more.","task":"Explain homecoming in 2-3 sentences with zero school-culture shorthand.","tips":["Define it by what happens: a week of events, a football game, a dance.","Tell them what they'd actually do and wear — that's their real question.","One tradition explained beats five named."],"focus":["audience","clarity"]},
    {"id":"audience-stu-early-13","level":"early","profession":"student","title":"The grade appeal that argues the rubric","scenario":"You believe your essay deserved better than a B-. Your draft email to your teacher argues how hard you worked and how long you spent. Your teacher grades against the rubric — effort isn't a rubric row.","task":"Rewrite the appeal in 3-4 sentences that speak to the rubric instead of the effort.","tips":["Point at specific rubric rows and where your essay meets them.","Quote your own essay as evidence, briefly.","Ask for a re-look at criteria, not sympathy for hours."],"focus":["audience","precision"],"placeholder":"Under 'use of evidence,' the rubric asks for three cited sources — my essay cites four:"},
    {"id":"audience-stu-early-14","level":"early","profession":"student","title":"The fundraiser email to families","scenario":"You wrote a fundraiser announcement for your teammates, full of team in-jokes and 'you know the drill.' Now the coach asks you to adapt it for an email to players' families, who need logistics and a reason to give.","task":"Rewrite the announcement in 3-4 sentences for parents and guardians.","tips":["Families need the basics spelled out: what, when, where, how to pay.","Replace in-jokes with the purpose: what the money makes possible for the team.","Warm and clear, not hyped."],"focus":["audience","clarity"]},
    {"id":"audience-stu-early-15","level":"early","profession":"student","title":"Onboarding the newest member","scenario":"A sophomore just joined your community-service club mid-semester. Your welcome message is full of references to 'the usual sign-up sheet,' 'points,' and 'the spring trip' — none of which they've encountered.","task":"Write a 3-4 sentence welcome that gives a brand-new member what they need for week one.","tips":["Cover their first real questions: when, where, what to bring, who to ask.","Explain 'points' in half a sentence if you must mention them.","One clear next action beats a full orientation."],"focus":["audience","structure"]},
    {"id":"audience-stu-early-16","level":"early","profession":"student","title":"The research question the librarian can work with","scenario":"You ask the school librarian for 'anything about World War II' for your history paper. She can't help until she knows your actual topic, your assignment, and what you've already found.","task":"Rewrite the request in 2-3 sentences that let the librarian actually help you.","tips":["Name the specific angle, the assignment type, and the due date.","Say what you already have, so you don't get duplicates.","The more precise the ask, the better the sources."],"focus":["audience","precision"],"placeholder":"I'm writing a 5-page paper on rationing on the home front, due in two weeks —"},
    {"id":"audience-stu-early-17","level":"early","profession":"student","title":"The activity nobody's heard of","scenario":"Your scholarship application asks you to describe an activity. You write 'Section leader, marching band, 3 years.' The reader has never seen your band and has no idea what a section leader does or why it matters.","task":"Describe the role in 2-3 sentences so its weight is obvious to a stranger.","tips":["Say what you actually did: taught, organized, led how many people.","Include scale: hours per week, size of the group.","Show the responsibility, don't just name the title."],"focus":["audience","precision"]},
    {"id":"audience-stu-early-18","level":"early","profession":"student","title":"The rule change, from the players' side","scenario":"Your coach asked you to relay a league rule change to the team: new substitution limits. Your draft quotes the league's formal wording. Your teammates need to know one thing — what changes for them on game day.","task":"Explain the change in 2-3 sentences focused on what players actually do differently.","tips":["Lead with the practical effect: what you can and can't do now.","Translate the rulebook wording into game situations.","Point to the full rule for anyone who wants it."],"focus":["audience","clarity"]},
    {"id":"audience-stu-early-19","level":"early","profession":"student","title":"Instructions for the next treasurer","scenario":"You're graduating and handing the club treasurer job to a junior. Your draft notes say things like 'do the form thing before deadlines' and 'ask the office about the account.' You know what those mean. They won't.","task":"Rewrite one instruction (2-3 sentences) so someone with zero context can follow it.","tips":["Name the actual form, the actual office, the actual date.","Write for a reader who can't ask you questions — you'll be gone.","One task, fully specified, beats five vague ones."],"focus":["audience","precision"]},
    {"id":"audience-stu-early-20","level":"early","profession":"student","title":"The book talk for people who haven't read it","scenario":"You're giving a two-minute book talk to convince classmates to read a novel you loved. Your draft dives into your favorite scene from chapter 20 — meaningless and spoiler-heavy for people on page zero.","task":"Write a 2-3 sentence pitch pitched at someone who knows nothing about the book.","tips":["Sell the situation and the question, not the ending.","Connect it to something your classmates already like.","Their question is 'why should I spend my time on this?' — answer that."],"focus":["audience","impact"]},
    {"id":"audience-stu-early-21","level":"early","profession":"student","title":"The exam-week request to your boss","scenario":"You need lighter hours at your cafe job during finals week. Your draft text is all about your stress and your grades. Your boss's actual problem: who covers your shifts and whether you'll flake.","task":"Write a 2-3 sentence message that solves your boss's problem, not just yours.","tips":["Lead with the specific change and the dates.","Offer the solution: who could cover, or which shifts you CAN keep.","Reliability is the message — show you've thought about coverage."],"focus":["audience","impact"],"placeholder":"For finals week (June 8-12), could I drop my Tuesday shift? Maya already said she can take it —"},
    {"id":"audience-stu-early-22","level":"early","profession":"student","title":"Your portfolio, explained for a rec letter","scenario":"Your math teacher agreed to write your college recommendation and asked you to describe your art portfolio so she can mention it. Your draft uses studio terms — 'mixed media,' 'negative space studies' — that won't survive translation into her letter.","task":"Describe the portfolio in 2-3 sentences she can quote or paraphrase confidently.","tips":["Describe what a viewer would see and what the work is about.","Give her one ready-made sentence she could lift directly.","Terms she can't explain will get cut — pre-translate them."],"focus":["audience","clarity"]},
    {"id":"audience-stu-early-23","level":"early","profession":"student","title":"The PA announcement everyone half-hears","scenario":"You're writing tomorrow's morning announcement for the canned-food drive. It will be read over the PA to 1,400 students who are packing up their bags and not listening. Your draft is five sentences of background.","task":"Write a 1-2 sentence announcement built for a distracted audience.","tips":["One point only: bring cans, where, by when.","Front-load the action — assume they hear only the first seconds.","Concrete beats clever on the PA."],"focus":["audience","concision"],"placeholder":"Bring canned food to your first-period class by Friday —"},
    {"id":"audience-stu-early-24","level":"early","profession":"student","title":"The cold email to a program director","scenario":"You're emailing the director of a summer engineering program with a question about eligibility. She's a stranger reading on her phone between meetings. Your draft assumes she knows your school, your grade, and your situation.","task":"Write a 3-sentence email that gives a stranger exactly the context needed to answer.","tips":["Identify yourself in half a sentence: grade, school type, applying for what.","Then the question, precisely.","Nothing extra — busy strangers reward brevity with replies."],"focus":["audience","concision"]},
    {"id":"audience-stu-early-25","level":"early","profession":"student","title":"Shadow day, without the acronyms","scenario":"A freshman is shadowing you in student government for a day. You catch yourself saying 'we'll swing by exec before gen assembly, then prep for the FAC meeting.' They nod politely, lost.","task":"Re-explain the day's plan in 2-3 sentences with every acronym unpacked.","tips":["Say what each meeting IS and what happens there.","Tell them their role: watch, ask questions, help with X.","The curse of knowledge hides in acronyms — hunt them down."],"focus":["audience","clarity"]}
  ],
  "structure-that-carries": [
    {"id":"structure-stu-early-01","level":"early","profession":"student","title":"The essay with five loose points","scenario":"Your draft essay on The Great Gatsby makes five separate observations that don't add up to anything. Your teacher's comment: 'What's your argument?' You need one governing claim with the observations grouped under it.","task":"Write a one-sentence thesis and name 2-3 buckets your observations group into.","tips":["The thesis is the roof; every paragraph holds it up.","Five points usually collapse into two or three real ones.","If an observation supports nothing, cut it — even a good one."],"focus":["structure","clarity"],"placeholder":"Gatsby's parties are the loneliest scenes in the novel. Three things show it:"},
    {"id":"structure-stu-early-02","level":"early","profession":"student","title":"SCQA for the refill station","scenario":"You're writing the student council proposal for a water-bottle refill station. You have facts everywhere: broken fountains, plastic waste, gym traffic, a $380 quote. It needs a shape: Situation, Complication, Question, Answer.","task":"Write a 4-sentence SCQA opening for the proposal.","tips":["Situation: what everyone already agrees is true.","Complication: what changed or what's broken.","Answer: your proposal, stated as the resolution of the question.","One sentence per beat keeps it tight."],"focus":["structure","impact"]},
    {"id":"structure-stu-early-03","level":"early","profession":"student","title":"PREP in class discussion","scenario":"Your English teacher asks the class whether the ending of the novel is hopeful. You have an opinion but you usually think out loud, wandering until you find your point. PREP: Point, Reason, Example, Point.","task":"Give a 4-sentence PREP answer to the question, spoken-style.","tips":["Point first: 'I think the ending is hopeful because...'","One reason, one specific moment from the text.","Land the plane: restate the point in new words."],"focus":["structure","clarity"],"placeholder":"I read the ending as hopeful. Here's why:"},
    {"id":"structure-stu-early-04","level":"early","profession":"student","title":"The fundraiser to-do pile","scenario":"Your club's car wash is in two weeks and the planning doc is a 14-item list in random order: buy sponges, ask the fire station about the lot, make posters, get a cash box, post on Instagram, find hoses... Nobody can tell who does what.","task":"Group the list into 3 named buckets and give each a one-line owner-and-deadline header.","tips":["Group by kind of work: location and permissions, supplies, promotion.","Name each bucket by its outcome, not 'misc.'","A grouped list assigns itself; a flat list assigns nothing."],"focus":["structure","clarity"]},
    {"id":"structure-stu-early-05","level":"early","profession":"student","title":"Five minutes on the French Revolution","scenario":"You have a five-minute history presentation on the causes of the French Revolution. Your notes are 20 facts in chronological order. Chronology isn't an argument — you need a governing idea and a few buckets.","task":"Write the governing sentence and name the 3 buckets of your presentation.","tips":["Pick a claim: 'Three pressures made revolution likely.'","Buckets should be parallel: economic, political, social — not one cause and two anecdotes.","Facts that fit no bucket don't make the cut."],"focus":["structure","clarity"]},
    {"id":"structure-stu-early-06","level":"early","profession":"student","title":"The college essay with three topics","scenario":"Your personal statement draft covers your grandmother, your robotics team, and your part-time job — three stories, no thread. Admissions readers finish it unsure what it was about. It needs one spine.","task":"Write one sentence naming the single idea your essay is about, and one sentence on which story carries it.","tips":["One essay, one idea. The other stories become one-line references or leave.","The spine is a quality of yours, not an event.","If you can't say it in a sentence, the reader can't either."],"focus":["structure","clarity"]},
    {"id":"structure-stu-early-07","level":"early","profession":"student","title":"The lab conclusion that carries","scenario":"Your physics lab conclusion is a paragraph of everything that happened, in order. Your teacher wants: claim, evidence, limitation. Yours has the evidence scattered and no claim at all.","task":"Write a 3-sentence conclusion: claim, then key evidence, then one limitation.","tips":["Sentence one states what the data shows — that's the claim.","Pick the strongest numbers as evidence; skip the play-by-play.","Naming a limitation is strength, not weakness."],"focus":["structure","precision"],"placeholder":"Our data supports the prediction: doubling the mass doubled the force, within 4%."},
    {"id":"structure-stu-early-08","level":"early","profession":"student","title":"PREP for 'why should we hire you?'","scenario":"You're interviewing for a summer camp counselor job. You know 'why should we hire you?' is coming, and your practice answers wander through your whole life story. You need a shape you can hold under nerves.","task":"Write a 4-sentence PREP answer you could say out loud.","tips":["Point: the one thing that makes you right for THIS job.","Example: a specific moment — a kid you helped, a group you led.","The closing point tells them what to remember about you."],"focus":["structure","impact"]},
    {"id":"structure-stu-early-09","level":"early","profession":"student","title":"The agenda that runs the meeting","scenario":"You're chairing this week's club meeting. Last week's meeting was 40 minutes of circular talk. Your agenda draft is a list of topics; it doesn't say which items are decisions, which are updates, and how long each gets.","task":"Write a 4-line agenda where each line has a label (decide/update), a time, and an owner.","tips":["Decisions first, while attention is fresh; updates can be quick.","A time next to each item is a promise to the room.","If an item has no owner, it won't happen."],"focus":["structure","concision"]},
    {"id":"structure-stu-early-10","level":"early","profession":"student","title":"Three contentions, one case","scenario":"Your debate case for banning single-use plastics in schools has six arguments of wildly different strength. Rounds are timed; judges flow three clean contentions better than six messy ones.","task":"Write your case's thesis and three parallel contention headlines.","tips":["Keep the three strongest, fold or drop the rest.","Make contentions parallel in form: each a short claim, not a topic.","The thesis should predict all three — that's the pyramid."],"focus":["structure","impact"],"placeholder":"Schools should ban single-use plastics for three reasons: cost, waste, and habit-building."},
    {"id":"structure-stu-early-11","level":"early","profession":"student","title":"The study guide worth sharing","scenario":"You're making the study guide for your group before the biology final. Your draft is your notes, retyped — six pages, no hierarchy. A good guide has the exam's big ideas as headers with details nested under them.","task":"Write the 3-4 top-level headers your guide should have, with one line on what goes under each.","tips":["Headers = what the test will actually ask about, not chapter numbers.","Nest ruthlessly: big idea, then mechanism, then example.","If everything is bold, nothing is."],"focus":["structure","concision"]},
    {"id":"structure-stu-early-12","level":"early","profession":"student","title":"Three questions, one email","scenario":"You're emailing your teacher three unrelated questions: one about the homework, one about the retake policy, one about the field trip form. Your draft weaves them into one tangled paragraph where each hides.","task":"Restructure the email: a one-line opener plus three numbered questions.","tips":["Numbered questions get numbered answers.","One topic per line — don't let questions blur together.","Order by urgency: what you need answered first goes first."],"focus":["structure","clarity"],"placeholder":"Three quick questions: 1)"},
    {"id":"structure-stu-early-13","level":"early","profession":"student","title":"Spirit week, by workstream","scenario":"You're coordinating your class's spirit week entry: costumes, hallway decorations, the skit, and the pep rally banner. Your planning message is one long paragraph mixing all four. Volunteers can't see where they're needed.","task":"Rewrite the plan as 3-4 labeled sections, each with one need and one deadline.","tips":["Section by workstream so people self-select.","Each section: what it is, what's needed, by when.","The message should let someone volunteer in one reply."],"focus":["structure","clarity"]},
    {"id":"structure-stu-early-14","level":"early","profession":"student","title":"The book report that argues","scenario":"Your book report draft summarizes the plot chapter by chapter. The assignment asks you to evaluate the book. A summary has the book's structure; an evaluation needs YOUR structure — a verdict with reasons.","task":"Write the verdict sentence and 2-3 reason-headlines your report would follow.","tips":["Your verdict is the governing idea; the plot becomes evidence.","Reasons should be about the book's craft, not just what happens.","Chapter order is the book's outline, not yours."],"focus":["structure","clarity"]},
    {"id":"structure-stu-early-15","level":"early","profession":"student","title":"SCQA opens the persuasive essay","scenario":"Your persuasive essay on later school start times opens with a dictionary definition of sleep. You've heard SCQA makes openings pull: Situation, Complication, Question — and your thesis as the Answer.","task":"Write a 3-4 sentence SCQA opening paragraph for the essay.","tips":["Situation: a fact the reader nods along to.","Complication: the tension that makes the topic urgent.","Your thesis arrives as the answer to a question the reader now has."],"focus":["structure","impact"]},
    {"id":"structure-stu-early-16","level":"early","profession":"student","title":"The three-part scholarship answer","scenario":"A scholarship prompt asks: 'Describe a challenge, what you did, and what you learned.' Your draft spends 80% on the challenge and crams action and lesson into the last line. The prompt hands you the structure — use it.","task":"Outline your answer in three sentences, one per part, weighted evenly.","tips":["The prompt's parts are your sections — mirror them.","Readers score against the prompt; missing parts cost points.","'What you did' deserves the most detail, not the least."],"focus":["structure","clarity"]},
    {"id":"structure-stu-early-17","level":"early","profession":"student","title":"From chat scroll to minutes","scenario":"Your club 'meeting' happened in a group chat — 60 messages of decisions, ideas, and memes. As secretary you need minutes people can act on: what was decided, what's open, who owes what.","task":"Write minutes with three labeled sections: Decided, Open, Action items (one line each).","tips":["Sort every message into decided, open, or action — discard the rest.","Action items need a name and a date or they're wishes.","Minutes are for the person who wasn't there."],"focus":["structure","concision"],"placeholder":"Decided: movie night is Friday the 14th, in the gym."},
    {"id":"structure-stu-early-18","level":"early","profession":"student","title":"The yearbook spread pitch","scenario":"You're pitching a yearbook spread about the school's custodial staff. Your pitch to the editor is a cloud of ideas: photos, interviews, a day-in-the-life timeline, fun facts. Editors approve pitches with a clear center and named parts.","task":"Write a one-sentence concept and list the 3 components of the spread.","tips":["The concept is the headline a reader would see.","Three components, each named by what the reader gets.","A pitch with structure looks finished; a cloud looks like work for the editor."],"focus":["structure","impact"]},
    {"id":"structure-stu-early-19","level":"early","profession":"student","title":"The activities list that groups itself","scenario":"Your resume for a summer program lists nine activities in random order: chess club, lifeguarding, food bank, coding camp, JV tennis, tutoring... The reader can't see a shape. Grouped, nine items become three strengths.","task":"Group the activities into 3 labeled categories and order them for this application.","tips":["Categories tell the reader what to conclude: service, leadership, technical.","Order groups by relevance to what you're applying for.","A label does the summarizing so the reader doesn't have to."],"focus":["structure","audience"]},
    {"id":"structure-stu-early-20","level":"early","profession":"student","title":"The case for a club room","scenario":"Your gaming club keeps getting bumped from borrowed classrooms. You're emailing the activities director to request a regular room assignment. You have complaints, membership numbers, and a specific room in mind — currently in no particular order.","task":"Write a 4-sentence SCQA email making the request.","tips":["Situation and complication in a sentence each — brief and factual.","The ask (which room, which day) is the answer; make it concrete.","End with the easiest possible next step for the director."],"focus":["structure","clarity"]},
    {"id":"structure-stu-early-21","level":"early","profession":"student","title":"PREP for the honor society interview","scenario":"Your National Honor Society interview will ask 'what does leadership mean to you?' Your honest answer is a jumble of half-thoughts. PREP gives you a container: Point, Reason, Example, Point.","task":"Write a 4-sentence PREP answer using one real example from your life.","tips":["Commit to a definition in sentence one — don't survey all possible answers.","The example is where you become memorable; make it specific.","Practice it aloud; PREP should sound natural, not recited."],"focus":["structure","impact"]},
    {"id":"structure-stu-early-22","level":"early","profession":"student","title":"The how-to speech in steps","scenario":"Your speech class assignment is a five-minute demonstration speech — you chose how to make pour-over coffee. Your draft mixes equipment, history, technique, and tips in whatever order they occurred to you.","task":"Write the speech's governing sentence and its 3-4 step headers in order.","tips":["Demonstration speeches are sequences: setup, action, result.","Fold trivia into steps or cut it — the structure is the steps.","Signpost each step aloud: 'First... Next... Finally.'"],"focus":["structure","clarity"]},
    {"id":"structure-stu-early-23","level":"early","profession":"student","title":"The handoff doc with three drawers","scenario":"You're writing the handoff document for next year's newspaper editor. Your draft is a brain-dump: passwords next to printer deadlines next to advice about the advisor. Useful things become findable when they're grouped.","task":"Name the 3-4 sections the doc should have and write the one-line purpose of each.","tips":["Group by when they'll need it: first week, monthly cycle, emergencies.","A section's name should answer 'when do I open this drawer?'","Advice and logins don't belong in the same paragraph."],"focus":["structure","audience"]},
    {"id":"structure-stu-early-24","level":"early","profession":"student","title":"Sorting the Q&A before it happens","scenario":"You present your capstone project Friday, with five minutes of questions after. You've brainstormed 12 things people might ask — a scary, shapeless list. Grouped, they're just three themes you can prepare.","task":"Group the likely questions into 3 themes and write a one-line prepared point for each.","tips":["Most questions are variants of a few themes: method, results, so-what.","Prepare the theme answer, not 12 scripts.","In the room, name the theme: 'That's about my data — here's the short answer.'"],"focus":["structure","clarity"]},
    {"id":"structure-stu-early-25","level":"early","profession":"student","title":"Who does what, in one message","scenario":"Your four-person group has to split an English project: research, slides, script, and presenting. Your draft message proposes the split but buries who-does-what inside long sentences about fairness.","task":"Write the division-of-labor message: one framing line, then one line per person with task and deadline.","tips":["One line per person: name, task, date. Nothing hides in a table like that.","The framing line states the goal and the final deadline.","Ask for objections by a specific time, then it's locked."],"focus":["structure","clarity"],"placeholder":"Here's the split so we hit Monday — speak up by tonight if you want to trade:"}
  ],
  "cut-to-the-bone": [
    {"id":"concise-stu-early-01","level":"early","profession":"student","title":"650 words, no more","scenario":"Your college essay draft is 720 words; the limit is 650. Every sentence feels necessary. But the draft has warm-up sentences, repeated ideas in different clothes, and phrases like 'in order to' doing the work of 'to.'","task":"State the 3 kinds of cuts you'd make first, with one example phrase each.","tips":["Cut the opening sentence and see if anyone misses it — often no one does.","Hunt doubled ideas: if two sentences make the same point, the better one stays.","'In order to' → 'to'; 'due to the fact that' → 'because.'"],"focus":["concision","clarity"]},
    {"id":"concise-stu-early-02","level":"early","profession":"student","title":"The apology sandwich","scenario":"Your extension request reads: 'I'm so sorry to bother you, and I completely understand if this isn't possible, and I feel terrible asking, but I was wondering if maybe I could possibly have one more day.' The ask is drowning in cushioning.","task":"Rewrite the request in one respectful, direct sentence.","tips":["One 'sorry' maximum — usually zero.","'I was wondering if maybe I could possibly' → 'Could I.'","Polite and direct can be the same sentence."],"focus":["concision","clarity"],"placeholder":"Could I have one more day on the lab report? I'd submit by Thursday 8am."},
    {"id":"concise-stu-early-03","level":"early","profession":"student","title":"The announcement nobody finishes","scenario":"Your draft club announcement is six sentences: a greeting, a joke, the news, background about the news, a repeat of the news, and a sign-off. The group chat will read the first line and scroll on.","task":"Cut the announcement to 2 sentences without losing the news.","tips":["News first, details second, everything else gone.","The joke costs more attention than it buys.","Saying it twice doesn't make it clearer — it makes it longer."],"focus":["concision","impact"]},
    {"id":"concise-stu-early-04","level":"early","profession":"student","title":"Seven minutes into five","scenario":"Your speech runs seven minutes; the assignment caps it at five. You wrote it to be read, not spoken — long sentences, three examples where one would land, and transitions like 'now I would like to move on to my next point.'","task":"Name the 3 cuts you'd make and rewrite one bloated transition in 5 words or fewer.","tips":["Keep the best example per point; cut the backups.","Spoken transitions can be two words: 'Next: cost.'","Reading aloud exposes what your eyes forgive."],"focus":["concision","structure"]},
    {"id":"concise-stu-early-05","level":"early","profession":"student","title":"The discussion post on stilts","scenario":"Your online class discussion post opens: 'I think that it could maybe be argued that the author is possibly trying to suggest...' Four hedges before the idea. You have a real point — it's just wearing armor.","task":"Rewrite the sentence with at most one hedge.","tips":["'I think that it could maybe be argued' → 'The author suggests.'","Keep one honest qualifier if the claim is genuinely uncertain.","Hedges multiply when we're nervous; delete them in revision."],"focus":["concision","clarity"],"placeholder":"The author suggests"},
    {"id":"concise-stu-early-06","level":"early","profession":"student","title":"The resume bullet that babbles","scenario":"Your resume bullet reads: 'Was responsible for helping to assist customers with various different needs and questions that they had during my shifts at the store.' Twenty-four words; about six carry meaning.","task":"Rewrite the bullet in 8 words or fewer, starting with a verb.","tips":["'Was responsible for helping to assist' → 'Helped' — or better, a stronger verb.","'Various different' is one word pretending to be two.","Numbers beat adjectives if you have them."],"focus":["concision","precision"],"placeholder":"Served 50+ customers per shift;"},
    {"id":"concise-stu-early-07","level":"early","profession":"student","title":"The paragraph-length text","scenario":"You're asking a classmate to bring your charger to school tomorrow. Your draft text is a paragraph: the backstory of where you left it, apologies, and the ask somewhere in the middle. It's a text, not a letter.","task":"Cut it to one sentence plus at most one detail.","tips":["Texts are read in two seconds — write for that.","The ask plus one logistic (which class, what it looks like) is complete.","Backstory answers questions nobody asked."],"focus":["concision","clarity"]},
    {"id":"concise-stu-early-08","level":"early","profession":"student","title":"Since the dawn of time","scenario":"Your history essay opens: 'Throughout the course of human history, people have always engaged in conflict for many various reasons.' It says nothing, and your teacher has read a thousand of these.","task":"Write a replacement opening sentence that starts with something specific.","tips":["Start where your actual argument starts — a date, a person, a fact.","If a sentence would work in any essay, it works in none.","Specific first sentences earn the reader's next minute."],"focus":["concision","impact"],"placeholder":"In 1917, three empires collapsed within months of each other."},
    {"id":"concise-stu-early-09","level":"early","profession":"student","title":"Redundant pairs in the lab report","scenario":"Your lab report is full of pairs: 'each and every trial,' 'first and foremost,' 'basic and fundamental,' 'combined together.' Each pair uses two words to do one word's job.","task":"Rewrite two of those phrases and state the rule you're applying.","tips":["When two words mean the same thing, keep the plainer one.","'Combined together' — together is hiding inside 'combined' already.","Science writing rewards the shortest accurate phrase."],"focus":["concision","precision"]},
    {"id":"concise-stu-early-10","level":"early","profession":"student","title":"Now I'm going to tell you about...","scenario":"Your presentation script keeps narrating itself: 'Now I'm going to talk about the causes.' 'Next I will show you a graph.' 'In this next slide you will see...' A third of your airtime is spent announcing the other two-thirds.","task":"Rewrite two of those meta-sentences as direct statements.","tips":["Don't announce the point — say the point.","'Now I'll talk about causes' → 'Three causes drove this.'","Slides people can see don't need narrating that they exist."],"focus":["concision","impact"],"placeholder":"Three causes drove this. First:"},
    {"id":"concise-stu-early-11","level":"early","profession":"student","title":"Halve the paragraph","scenario":"A body paragraph in your English essay runs nine sentences. Reread honestly: two sentences repeat the topic sentence, one is a quote longer than it needs to be, and two explain what the quote 'is trying to say' twice.","task":"Describe which 4-5 sentences survive and why.","tips":["Topic sentence, evidence, one interpretation, link back — that's often enough.","Quote only the words doing the work; ellipses are allowed.","Explaining a quote twice means the first explanation wasn't sure of itself."],"focus":["concision","structure"]},
    {"id":"concise-stu-early-12","level":"early","profession":"student","title":"The counselor email, boiled down","scenario":"Your email asking your counselor to review your college list is 12 sentences of context: your stress, your parents' opinions, your shifting preferences. The counselor needs one thing: what you want from the meeting.","task":"Rewrite the email in 3 sentences.","tips":["Sentence one: the ask and a proposed time.","Sentence two: the one piece of context that changes their prep.","Everything else is for the meeting itself."],"focus":["concision","audience"],"placeholder":"Could we meet this week to review my college list? I've added two schools since we last talked."},
    {"id":"concise-stu-early-13","level":"early","profession":"student","title":"Nominalizations in the minutes","scenario":"Your student council minutes read: 'A discussion was had regarding the implementation of a decision about the utilization of funds.' Actions became nouns and the sentence died. People did things — say so.","task":"Rewrite the sentence with verbs doing the work.","tips":["'Made a decision' → 'decided'; 'utilization' → 'use.'","Find who did what: 'The council voted to spend...'","If a sentence has no live verb, it has no energy."],"focus":["concision","clarity"],"placeholder":"The council voted to spend the $200 on"},
    {"id":"concise-stu-early-14","level":"early","profession":"student","title":"The caption that won't fit","scenario":"Your yearbook caption is 40 words; the layout allows 18. Draft: 'Members of the varsity soccer team celebrate together happily after scoring the winning goal in the final championship game of their amazing season.'","task":"Rewrite the caption in 18 words or fewer without losing the facts.","tips":["'Celebrate together happily' — celebration is together and happy already.","'Winning goal in the final championship game' has a shorter true version.","Keep the who, the what, the moment; cut the adjectives."],"focus":["concision","precision"]},
    {"id":"concise-stu-early-15","level":"early","profession":"student","title":"210 words into 150","scenario":"The scholarship form allows 150 words for 'describe your community involvement.' Your draft is 210. The extra 60 words are throat-clearing, one repeated idea, and generalities like 'making a difference in various ways.'","task":"Name the first 3 cuts you'd make, quoting the kind of phrase each removes.","tips":["Cut the intro sentence that restates the prompt.","'Making a difference in various ways' — replace with the actual ways, which are shorter.","Word limits are edited FOR you if you don't edit first — and they cut the wrong things."],"focus":["concision","precision"]},
    {"id":"concise-stu-early-16","level":"early","profession":"student","title":"One line for the club's post","scenario":"Your club's Instagram post about Thursday's bake sale has a caption that's four sentences long. On a feed, you get one line before '...more' hides the rest — and nobody taps more.","task":"Write the caption's first line (under 12 words) so it works alone.","tips":["The first line must contain the what, when, where.","Front-load: 'Bake sale Thursday' beats 'Hey everyone! Guess what's happening!'","Hashtags aren't information."],"focus":["concision","impact"],"placeholder":"Bake sale Thursday, main lobby, 3pm — cookies from $1."},
    {"id":"concise-stu-early-17","level":"early","profession":"student","title":"Sort of, kind of, very","scenario":"Your persuasive essay is padded with 'sort of,' 'kind of,' 'very,' 'really,' 'quite,' and 'pretty much.' Each one blurs the sentence it lives in. 'The policy is very unfair and kind of hurts a lot of students.'","task":"Rewrite that sentence with zero intensity padding.","tips":["'Very unfair' is weaker than 'unfair' said plainly.","Replace 'a lot of' with the number if you know it.","Intensifiers are volume knobs; facts are the music."],"focus":["concision","precision"],"placeholder":"The policy is unfair: it costs 200 students their"},
    {"id":"concise-stu-early-18","level":"early","profession":"student","title":"The thank-you that gushes","scenario":"After your job interview at the pool, you're writing a thank-you email. Your draft thanks them four different ways across six sentences. Gratitude has diminishing returns after sentence one.","task":"Write a 3-sentence thank-you: thanks, one specific detail from the conversation, availability.","tips":["One genuine thank-you, then move.","The specific detail proves you were present; that's the memorable part.","Close with the practical: when you can start."],"focus":["concision","audience"]},
    {"id":"concise-stu-early-19","level":"early","profession":"student","title":"The ending that won't end","scenario":"Your speech has three endings: 'So in conclusion...', then a summary, then 'and finally I just want to say...', then another summary. The audience checked out at the first false landing.","task":"Write one closing sentence — the only one you'll keep.","tips":["End once. The strongest closing line, then silence.","'In conclusion' plus a repeat of everything is not a conclusion.","A short last line hits harder than a paragraph."],"focus":["concision","impact"]},
    {"id":"concise-stu-early-20","level":"early","profession":"student","title":"Status update, bulleted","scenario":"Your update to the group project chat is a wall of text covering what's done, what's blocked, and what you need. Nobody will excavate the asks from the paragraph.","task":"Rewrite it as a 3-bullet message: done, blocked, need.","tips":["One bullet per category, one line per bullet.","Put the 'need' bullet where nobody can miss it — with a name attached.","Walls of text get skimmed; bullets get read."],"focus":["concision","structure"],"placeholder":"Done: my two sections drafted. Blocked:"},
    {"id":"concise-stu-early-21","level":"early","profession":"student","title":"As previously stated","scenario":"Your essay repeats itself with connectors like 'as previously stated,' 'as mentioned before,' and 'again, it is important to note.' If you're re-stating it, either it wasn't clear the first time or it doesn't need saying twice.","task":"State the rule you'd apply, and rewrite one 'as previously stated' sentence.","tips":["Say it once, in the right place, well.","If a point must echo, echo it in new words that ADD something.","'It is important to note' — if it's important, the sentence should prove it."],"focus":["concision","clarity"]},
    {"id":"concise-stu-early-22","level":"early","profession":"student","title":"About me, in 100 words","scenario":"The summer program application wants a 100-word bio. Your draft is 160 words and starts with your birth. The reader needs: who you are now, what you're into, what you're aiming at.","task":"Write the first 2 sentences of the 100-word version.","tips":["Start with the present, not your origin story.","One interest with detail beats four interests listed.","Every sentence in a bio pays rent or leaves."],"focus":["concision","audience"]},
    {"id":"concise-stu-early-23","level":"early","profession":"student","title":"The subject line does the work","scenario":"You're emailing your teacher that you'll miss Friday's review session. Draft subject: 'Question.' Draft body: five sentences. The subject could carry half the message and the body could be two lines.","task":"Write the subject line and a 2-sentence body.","tips":["Subject: specific enough to act on — 'Missing Friday review (dentist).'","The body adds only what the subject can't hold.","Teachers triage by subject line; vague ones sink."],"focus":["concision","clarity"],"placeholder":"Subject: Missing Friday's review session"},
    {"id":"concise-stu-early-24","level":"early","profession":"student","title":"This might be a dumb question","scenario":"You want to ask a question in physics class, and your planned opener is: 'Sorry, this might be a dumb question, and maybe you already covered this, but I was just wondering...' Fifteen words of self-defense before the question.","task":"Write the question with zero preamble, as you'd say it aloud.","tips":["Ask it straight: the question was never dumb.","Preamble invites the class to tune out before the good part.","If context is needed, one clause: 'On the friction example — why...'"],"focus":["concision","clarity"]},
    {"id":"concise-stu-early-25","level":"early","profession":"student","title":"The slide with 80 words on it","scenario":"One slide in your group's deck has 80 words — full sentences you plan to read aloud. The audience reads faster than you talk, finishes early, and stops listening. The slide needs one takeaway; you carry the rest.","task":"Write the slide's one takeaway line (under 10 words) to replace the paragraph.","tips":["Slide = headline; speaker = paragraph.","If the audience remembers one line from this slide, write THAT.","Data can stay; sentences about the data belong in your mouth."],"focus":["concision","impact"],"placeholder":"Recycling bins cut cafeteria trash 40% in one month."}
  ],
  "precision-and-evidence": [
    {"id":"precision-stu-early-01","level":"early","profession":"student","title":"'We need more funding'","scenario":"Your drama club's request to the activities office says 'we need more funding for the spring play.' The office can't act on 'more.' You actually need $340: $220 for set materials, $80 for costume rentals, $40 for printing programs.","task":"Rewrite the request in 2 sentences with the exact amount and what it buys.","tips":["Name the number and break it into its parts.","Attach each dollar to a visible outcome.","'More' invites a no; '$340 for these three things' invites a decision."],"focus":["precision","clarity"],"placeholder":"We're requesting $340 for the spring play: $220 for set materials,"},
    {"id":"precision-stu-early-02","level":"early","profession":"student","title":"'I worked really hard'","scenario":"Your college essay says you 'worked really hard' at your grocery job 'while juggling a lot of responsibilities.' The reader learns nothing. The truth: 20 hours a week, closing shifts twice a week, while taking two AP classes.","task":"Rewrite the sentence with the specifics doing the work.","tips":["'Really hard' is a claim; '20 hours a week' is a fact.","Let the reader conclude 'hardworking' — don't announce it.","Specifics are also more interesting to read."],"focus":["precision","impact"],"placeholder":"Twice a week I closed the store at 11pm, then finished calc homework"},
    {"id":"precision-stu-early-03","level":"early","profession":"student","title":"The fundraiser report with no numbers","scenario":"Your report to the club says the fundraiser 'went great and raised a good amount.' The actual results: $412 raised, 61 items sold, 9 volunteers, and the top seller was the banana bread at $45 total.","task":"Write a 2-sentence report where every claim carries a number.","tips":["Replace 'great' with the figure and the goal it beat.","One breakdown detail makes the report credible and repeatable.","Numbers travel: people will quote your report correctly."],"focus":["precision","concision"]},
    {"id":"precision-stu-early-04","level":"early","profession":"student","title":"'A lot hotter' isn't data","scenario":"Your chemistry lab conclusion says the reaction with the catalyst got 'a lot hotter, way faster.' Your data table says: 41°C vs 28°C peak, reached in 35 seconds vs 2 minutes. The numbers were sitting right there.","task":"Rewrite the conclusion sentence using the measurements.","tips":["Pull the exact figures from your own table.","Comparative claims need both numbers, not just the winner.","'Way faster' can't be checked; '35 seconds vs 2 minutes' can."],"focus":["precision","clarity"],"placeholder":"With the catalyst, the reaction peaked at 41°C in 35 seconds, versus 28°C"},
    {"id":"precision-stu-early-05","level":"early","profession":"student","title":"The case for playing time","scenario":"You want to ask your coach for more minutes. Your instinct: 'I feel like I've been playing really well lately.' Your actual case: you've scored in three straight JV games and led the team in steals the last two.","task":"Make the case in 2 sentences using only checkable facts.","tips":["Feelings ask for favors; records ask for decisions.","Pick stats the coach tracks and can verify.","End with a specific, modest ask — one game, one chance."],"focus":["precision","impact"]},
    {"id":"precision-stu-early-06","level":"early","profession":"student","title":"'Helped customers' — how many? with what?","scenario":"Your resume says 'helped customers at a busy ice cream shop.' In one summer you served hundreds of customers a shift on weekends, trained two new hires, and handled the register solo for closing.","task":"Rewrite the line as 1-2 bullets with numbers a manager can picture.","tips":["'Busy' becomes a number: customers per shift, weekend rushes.","Training and closing solo are facts that outrank adjectives.","Every bullet should survive the question 'says who?'"],"focus":["precision","concision"],"placeholder":"Served 200+ customers per weekend shift; trained 2 new hires"},
    {"id":"precision-stu-early-07","level":"early","profession":"student","title":"The claim with no anchor","scenario":"Your history essay claims 'the war changed everything for women workers.' Your teacher circles it: 'everything? says who?' You have the evidence: women in the US workforce rose from about 27% to 37% between 1940 and 1945.","task":"Rewrite the claim anchored to the statistic and its dates.","tips":["Scale the claim to fit the evidence you actually have.","Dates and sources turn opinion into history.","A smaller, supported claim beats a grand, naked one."],"focus":["precision","clarity"]},
    {"id":"precision-stu-early-08","level":"early","profession":"student","title":"'Tons of fun' recruits nobody","scenario":"Your club fair pitch says chess club is 'tons of fun with a great community.' Every club says that. What's true and specific: Friday blitz tournaments, a ladder board, pizza on tournament days, and beginners welcome with taught openings.","task":"Rewrite the pitch in 2 sentences using only specifics.","tips":["Specifics are the only differentiator at a club fair.","'Beginners welcome' plus HOW you welcome them is believable.","One vivid detail (the ladder board) outsells three adjectives."],"focus":["precision","audience"]},
    {"id":"precision-stu-early-09","level":"early","profession":"student","title":"The raise conversation","scenario":"You want to ask for a raise at the cafe after ten months. Your draft says you've 'been there a while and taken on more.' The facts: 10 months, you open alone on Sundays, you were trained on inventory last month, and you've never missed a shift.","task":"Write the 2-3 sentence ask using the facts, ending with a specific number.","tips":["List what changed since your rate was set — that's the argument.","'Never missed a shift' is a metric; use it.","Name the raise you're asking for; vague asks get vague answers."],"focus":["precision","impact"],"placeholder":"In ten months I've never missed a shift, I open solo on Sundays, and"},
    {"id":"precision-stu-early-10","level":"early","profession":"student","title":"'The test was unfair' — show it","scenario":"Half your class thinks Friday's test was unfair, and you're the one emailing the teacher. 'It was unfair' will bounce. What's checkable: three questions covered section 7.4, which the syllabus listed for AFTER the test.","task":"Write a 2-sentence email making the specific, checkable case.","tips":["Point to the exact questions and the exact syllabus line.","Ask for a specific remedy: those questions excluded, or reviewed.","One verifiable fact outweighs twenty students' feelings."],"focus":["precision","clarity"],"placeholder":"Questions 12-14 covered section 7.4, which the syllabus schedules for next week —"},
    {"id":"precision-stu-early-11","level":"early","profession":"student","title":"The graph label that says nothing","scenario":"Your science fair board has a graph titled 'Results' with an axis labeled 'amount.' A judge stopping for 20 seconds learns nothing. The graph actually shows plant growth in cm over 6 weeks under three light conditions.","task":"Write the graph's new title and both axis labels, precisely.","tips":["The title should state the finding, not the word 'Results.'","Axes carry units or they carry confusion.","A well-labeled graph presents itself when you're not standing there."],"focus":["precision","clarity"]},
    {"id":"precision-stu-early-12","level":"early","profession":"student","title":"The attendance appeal","scenario":"The attendance office flagged you for unexcused absences, but two of the four dates are wrong — you were at a school debate tournament on both. 'I was definitely at school events' won't fix the record. Dates and documentation will.","task":"Write a 2-3 sentence appeal naming the exact dates and the proof.","tips":["Name each date and where you actually were.","Point to the record that proves it: tournament roster, coach's confirmation.","Ask for the specific correction, not general understanding."],"focus":["precision","structure"]},
    {"id":"precision-stu-early-13","level":"early","profession":"student","title":"'Everyone thinks' — do they?","scenario":"Your op-ed for the school paper claims 'everyone hates the new schedule.' Your actual survey of 80 students found 62% dislike it, 24% like it, 14% neutral. 'Everyone' is doing dishonest work for you.","task":"Rewrite the claim using your survey numbers, including the sample size.","tips":["Report the split, not just your side.","Sample size makes the number honest: '62% of 80 surveyed.'","Precise claims survive angry letters to the editor; 'everyone' doesn't."],"focus":["precision","impact"],"placeholder":"Of 80 students we surveyed, 62% dislike the new schedule —"},
    {"id":"precision-stu-early-14","level":"early","profession":"student","title":"What, so what, now what","scenario":"Your environmental club measured cafeteria waste for a week: 38 bags of trash, and by your sorting, about a third was recyclable. You're presenting to the student council. Data alone isn't a presentation — it needs an insight and an ask.","task":"Write 3 sentences: What (the finding), So What (why it matters), Now What (the ask).","tips":["What: the single number that matters most.","So What: translate it — bags per month, cost, missed recycling.","Now What: one concrete, cheap first step."],"focus":["precision","structure"]},
    {"id":"precision-stu-early-15","level":"early","profession":"student","title":"The budget with line items","scenario":"Your request for the club's pizza social says 'around $60 for food and stuff.' The treasurer keeps rejecting 'and stuff.' The real plan: 4 pizzas at $11, drinks $10, plates and napkins $6.","task":"Write the request as a one-line total plus line items.","tips":["'Around' becomes exact once you list the parts.","Line items show you did the work — approvals follow.","If costs might vary, say which line and by how much."],"focus":["precision","concision"],"placeholder":"Requesting $60: 4 pizzas ($44),"},
    {"id":"precision-stu-early-16","level":"early","profession":"student","title":"'Soon' is not a date","scenario":"Your group asks when your section of the project will be done. Your instinct: 'soon, almost there.' The truth you can commit to: draft done tonight, sources formatted by tomorrow 6pm.","task":"Write the 1-2 sentence reply with real timestamps.","tips":["'Soon' transfers your uncertainty to everyone else's plans.","Commit to the time you're 90% sure of, not your best case.","A date lets teammates plan; 'almost' makes them nag."],"focus":["precision","clarity"]},
    {"id":"precision-stu-early-17","level":"early","profession":"student","title":"The skeptic test","scenario":"Your persuasive essay's key claim: 'later start times would obviously improve grades.' Read it as your most skeptical classmate: Obviously? Improve by how much? Says who? You have one study showing a modest GPA gain — that's your real ammunition.","task":"Rewrite the claim so a skeptic finds nothing loose to grab.","tips":["Delete 'obviously' — it's where skeptics aim first.","Scale the verb to the evidence: 'improve' → what the study showed.","Cite the source in the sentence, not just the bibliography."],"focus":["precision","impact"]},
    {"id":"precision-stu-early-18","level":"early","profession":"student","title":"The tutoring flyer's big promise","scenario":"Your flyer offering math tutoring says 'guaranteed to raise your grade!' You can't guarantee that, and parents know it. What's true: you've tutored 6 students, you got an A in the class, and you charge half what the tutoring center does.","task":"Rewrite the flyer's pitch line using only claims you can back.","tips":["Replace the guarantee with your verifiable track record.","Price and credentials are facts — lead with them.","Overclaiming costs trust; precision builds it."],"focus":["precision","audience"]},
    {"id":"precision-stu-early-19","level":"early","profession":"student","title":"The hours letter, exactly","scenario":"You're drafting the volunteer-hours confirmation for the shelter coordinator to sign. Your draft says you 'volunteered regularly for a long time doing various tasks.' A signable letter needs exact hours, dates, and duties.","task":"Write the 2-sentence body of the letter with exact figures and duties.","tips":["Total hours, date range, frequency — all three.","Name the two or three actual duties, not 'various tasks.'","Write it so the coordinator can sign without edits."],"focus":["precision","concision"],"placeholder":"Between September 2025 and May 2026, [name] volunteered 42 hours"},
    {"id":"precision-stu-early-20","level":"early","profession":"student","title":"'The bus is always late'","scenario":"You're emailing the transportation office about your bus. 'Always late' will be dismissed — buses run late sometimes. Your log from the past two weeks: late 7 of 10 days, by 12-25 minutes, making you miss the start of first period 4 times.","task":"Write a 2-3 sentence complaint using the log.","tips":["'Always' is refutable; '7 of 10 days' is not.","Connect the delay to the consequence: missed class time.","Offer the log itself — evidence you'll share changes the tone."],"focus":["precision","impact"],"placeholder":"Bus 14 arrived 12-25 minutes late on 7 of the last 10 school days —"},
    {"id":"precision-stu-early-21","level":"early","profession":"student","title":"The progress report with substance","scenario":"Your monthly report to the club advisor says the mentoring program is 'going well with good participation.' The reality you can count: 11 active pairs, 3 pairs went inactive, average of 2 meetings per pair this month.","task":"Write a 2-sentence report with the real numbers, including the unflattering one.","tips":["Include the number that isn't flattering — it buys trust for the rest.","'Good participation' means nothing next month; '11 pairs' can be tracked.","Numbers make the next question productive: why did 3 go inactive?"],"focus":["precision","clarity"]},
    {"id":"precision-stu-early-22","level":"early","profession":"student","title":"'I'm a leader' — prove it in one example","scenario":"In your college interview you plan to say 'I'm a real leader at my school.' The interviewer hears that fifty times a week. Your evidence: you rebuilt the recycling program's volunteer base from 4 students to 19 in one semester.","task":"Write the 2-sentence spoken answer that leads with the example, not the label.","tips":["Tell the example and let 'leader' go unsaid — it lands harder.","Numbers in speech should be simple: 'from four volunteers to nineteen.'","One deep example beats three shallow ones in an interview."],"focus":["precision","impact"]},
    {"id":"precision-stu-early-23","level":"early","profession":"student","title":"'Recently' in the lab notebook","scenario":"Your lab notebook entries say things like 'recently the readings drifted' and 'a while ago we recalibrated.' Next month, when you write the report, 'recently' will be meaningless. Notebooks exist to pin things to dates.","task":"Rewrite the two entries with dates and specifics.","tips":["Every entry gets a date; every change gets a number.","'Drifted' — from what to what?","Write for the future reader who has forgotten everything: you."],"focus":["precision","clarity"]},
    {"id":"precision-stu-early-24","level":"early","profession":"student","title":"One takeaway from the poll","scenario":"Student council polled 200 students on cafeteria options with 8 questions. You're reporting results at the meeting. Reading all 8 breakdowns will lose the room. One finding matters most: 71% would buy breakfast if it were sold before first period.","task":"Write the 2-sentence report: the one takeaway, then what you propose doing about it.","tips":["Lead with the single strongest finding, not the methodology.","Numbers plus an action = a decision; numbers alone = homework for the audience.","The other 7 results go in a doc you link, not the meeting."],"focus":["precision","structure"],"placeholder":"The headline: 71% of 200 students polled would buy breakfast before first period."},
    {"id":"precision-stu-early-25","level":"early","profession":"student","title":"The banquet line that needs stats","scenario":"You're speaking at the season-end banquet and your draft says the team 'improved so much this season.' The scorebook says it: 3 wins last season, 11 this season, and the first playoff appearance in 6 years.","task":"Rewrite the line with the season's numbers.","tips":["The record IS the emotion — let the numbers carry it.","'First playoff appearance in six years' is a story in seven words.","Delivered aloud, round numbers land better than decimals."],"focus":["precision","impact"],"placeholder":"Last year we won three games. This year: eleven, and"}
  ],
  "executive-presence": [
    {"id":"presence-stu-early-01","level":"early","profession":"student","title":"Recommend a theme, don't read a menu","scenario":"The dance committee asked you to research themes and report back. You found four workable options. Reading all four with pros and cons makes the meeting decide from scratch — you did the research, so you have the best-informed opinion in the room.","task":"Write a 2-3 sentence recommendation that names your pick first, with the runner-up as backup.","tips":["'I recommend X because...' — then the menu, briefly, if asked.","Your research earns you a point of view; use it.","Offering one backup shows judgment, not indecision."],"focus":["impact","clarity"],"placeholder":"I recommend 'Old Hollywood' — it's the cheapest to decorate and"},
    {"id":"presence-stu-early-02","level":"early","profession":"student","title":"Pick the topic like you mean it","scenario":"Your group has to choose a research topic today or lose points. You've compared the three finalists and one clearly has the best sources. Your instinct is to say 'I'm fine with whatever you all think.' The group is waiting for someone to decide.","task":"Write the 2-sentence message that states your pick and the reason.","tips":["'I'm fine with whatever' outsources thinking the group needs from you.","State the pick, the one deciding reason, and invite a veto by tonight.","Groups follow the person with a reason."],"focus":["clarity","impact"]},
    {"id":"presence-stu-early-03","level":"early","profession":"student","title":"'What do you think?' means take a stance","scenario":"Your English teacher asks you directly: 'Do you think the protagonist deserved her ending?' Your habit is to say 'I can see both sides' and summarize other people's points. The question asked what YOU think.","task":"Write a 2-3 sentence spoken answer that commits to a position.","tips":["Pick the side you lean toward — leaning counts as a position.","Acknowledge the other side in one clause AFTER your claim.","'Both sides' is an observation; class discussion wants an argument."],"focus":["clarity","impact"],"placeholder":"She deserved better, and I think the author knows it —"},
    {"id":"presence-stu-early-04","level":"early","profession":"student","title":"Signpost the five minutes","scenario":"Your presentation covers three arguments for community solar. Last time you presented, the class got lost between points because nothing marked where one ended and the next began. Signposts are the difference between a tour and a wander.","task":"Write your opening sentence plus the three spoken signposts you'll use.","tips":["Opening: 'Three reasons — cost, jobs, and independence.'","Each signpost is short and numbered: 'Second: jobs.'","The audience relaxes when they know where they are in the map."],"focus":["structure","clarity"]},
    {"id":"presence-stu-early-05","level":"early","profession":"student","title":"One proposal, owned","scenario":"At student council you want to fix the chaotic club-fair scheduling. Your draft pitch lists four things council 'could maybe consider possibly doing.' Committees don't act on clouds of options — they act on one owned proposal.","task":"Write a 2-3 sentence pitch proposing ONE fix, in first person, with your name on it.","tips":["'I propose we...' — first person, present tense, no maybe.","Offer to run it: ownership is what makes proposals credible.","The other three ideas keep for later meetings."],"focus":["impact","structure"]},
    {"id":"presence-stu-early-06","level":"early","profession":"student","title":"Fact, then judgment, labeled","scenario":"In your current-events debate you keep blending facts and opinions in single breaths: 'The policy failed and it was a stupid idea anyway.' Your teacher pushes: which part is documented, which part is your view?","task":"Rewrite the point as 2 sentences: one verifiable fact, then your judgment labeled as judgment.","tips":["'The data shows X. My read is Y.' — two different kinds of sentence.","Labeling judgment as judgment makes it stronger, not weaker.","Blended claims are easy to attack at their weakest half."],"focus":["clarity","precision"],"placeholder":"Enrollment dropped 15% in the two years after the policy. My judgment: the policy caused most of that, because"},
    {"id":"presence-stu-early-07","level":"early","profession":"student","title":"Car wash or bake sale — pick","scenario":"Your club has to choose its spring fundraiser and you've run the numbers: the car wash historically nets about $350, the bake sale about $150, but the car wash needs 12 volunteers to the bake sale's 5. You're presenting at the meeting.","task":"Write a 2-3 sentence spoken recommendation that picks one and handles the tradeoff.","tips":["Recommend, then name the tradeoff yourself before someone else does.","Numbers first, feelings nowhere.","End with the condition: 'if we can get 12 names tonight.'"],"focus":["impact","precision"]},
    {"id":"presence-stu-early-08","level":"early","profession":"student","title":"The strength question, unhedged","scenario":"Practicing for your camp counselor interview, you answer 'what's your greatest strength?' with: 'Um, I guess people say I'm sort of good with kids? I don't know, I try.' Every hedge takes a bite out of the answer.","task":"Write the answer as 2 confident sentences with one concrete proof.","tips":["Claim the strength in plain words: 'I'm good with kids.'","Follow immediately with the proof — that's what makes confidence honest.","'People say' and 'I guess' hand your answer to someone else."],"focus":["clarity","impact"],"placeholder":"I'm good with kids — last summer I ran the craft table for twenty 7-year-olds"},
    {"id":"presence-stu-early-09","level":"early","profession":"student","title":"End the survey with a recommendation","scenario":"You presented your club's survey results to the officers: clean charts, honest numbers. Then you sat down. The room said 'interesting' and moved on. Data without a recommendation is a book report; you were the only one who studied the data.","task":"Write the closing 2 sentences you should have said: the recommendation the data supports.","tips":["'Based on this, we should...' is the sentence the data was for.","Pick the one action the numbers most clearly support.","Presenters who recommend get invited back as deciders."],"focus":["impact","structure"]},
    {"id":"presence-stu-early-10","level":"early","profession":"student","title":"Propose the format, don't beg for it","scenario":"You want to ask your history teacher to accept a documentary video instead of the standard essay. Your draft grovels: 'if it's not too much trouble, I totally understand if not...' A proposal with success criteria respects the teacher more than begging does.","task":"Write a 2-3 sentence proposal that states the plan and how it meets the assignment's goals.","tips":["Map your format to the rubric: same thesis, same sources, same rigor.","Propose the checkpoint: outline approved by Friday.","Confidence plus criteria is easier to approve than apology."],"focus":["impact","audience"]},
    {"id":"presence-stu-early-11","level":"early","profession":"student","title":"The captain explains the lineup","scenario":"As captain you set the relay order, and a teammate who got moved to third leg is visibly unhappy. Mumbling 'coach and I just figured...' undercuts the decision AND you. The order has a reason: her splits are strongest on the turns.","task":"Write the 2-sentence explanation you'd say to her: decision, reason, standing behind it.","tips":["Own it in first person: 'I put you third because...'","The reason should be about the race, specific and true.","Steady beats apologetic — you can care about her feelings and keep the call."],"focus":["clarity","impact"]},
    {"id":"presence-stu-early-12","level":"early","profession":"student","title":"Defend the interpretation you actually hold","scenario":"In your book club you said the ending is a tragedy, and two people immediately disagreed. Your instinct is to retreat: 'yeah, I mean, I could be wrong.' You're not wrong — you have the final chapter on your side.","task":"Write the 2-3 sentence spoken response that holds your ground with evidence.","tips":["Hold the claim; upgrade the support.","Point at the page: 'The last image is the empty house — that's not a happy ending.'","You can honor their reading and keep yours: 'I see the case, and here's why mine holds.'"],"focus":["impact","precision"]},
    {"id":"presence-stu-early-13","level":"early","profession":"student","title":"The honest read on the draft","scenario":"Your group asks what you think of the project draft. You think the middle section is weak and unsupported — but you don't want to be harsh, so you're about to say 'looks good!' A labeled judgment helps; fake approval hurts everyone's grade.","task":"Write a 2-3 sentence assessment that gives your honest judgment, labeled as your view, with the fix.","tips":["'My honest read:' signals judgment, invites discussion.","Name the section and the problem, then the concrete fix.","Kind and honest is the combination; pick both."],"focus":["clarity","impact"],"placeholder":"My honest read: the middle section asserts a lot without sources. If we add"},
    {"id":"presence-stu-early-14","level":"early","profession":"student","title":"'It depends' — then say on what","scenario":"A freshman asks you whether they should take AP Biology next year. It genuinely depends — but 'it depends' alone is a non-answer. A useful answer names the conditions and then commits for each branch.","task":"Write a 2-3 sentence answer with the shape: 'It depends on X. If X, do this. If not, do that.'","tips":["Name the single factor that matters most.","Commit inside each branch — that's what makes conditional advice usable.","'It depends' opens an answer; it can't be the whole answer."],"focus":["clarity","structure"]},
    {"id":"presence-stu-early-15","level":"early","profession":"student","title":"Open the meeting with the map","scenario":"You're running today's yearbook staff meeting. Last week's meeting started with 'so... anyone have anything?' and dissolved. This week you have three items and 25 minutes, and the room should know the plan in the first ten seconds.","task":"Write the meeting-opening 2 sentences: the three items, times, and what needs deciding today.","tips":["'Three things today: A, B, C. We need to decide A before we leave.'","The map creates authority; the vague open surrenders it.","Time-box out loud — the room helps you keep the promise."],"focus":["structure","impact"],"placeholder":"Three things in 25 minutes: cover vote, senior-page deadline, and photo assignments."},
    {"id":"presence-stu-early-16","level":"early","profession":"student","title":"The conclusion with limits, not apologies","scenario":"At the science fair a judge asks what you concluded. You start: 'Well, our sample was small so it might not mean anything, but...' You've disqualified your own result before saying it. Confident and honest can coexist: conclusion first, limits second.","task":"Write the 2-sentence spoken answer: your conclusion stated plainly, then its limit stated precisely.","tips":["Lead with what you found — you did the work.","State the limit as a fact (n=12), not an apology ('it might be meaningless').","Judges reward calibrated confidence, not self-erasure."],"focus":["impact","precision"],"placeholder":"We found the mint extract cut bacterial growth roughly in half. With only 12 dishes, I'd want"},
    {"id":"presence-stu-early-17","level":"early","profession":"student","title":"The endorsement with a spine","scenario":"You're endorsing a friend for club president at the election meeting. Your draft is generic: 'she's nice, hardworking, and cares a lot.' Every endorsement says that. Yours can carry weight because you name what she actually did.","task":"Write a 2-3 sentence endorsement built on one specific act of leadership you witnessed.","tips":["One concrete story beats five adjectives.","Say the conclusion plainly: 'That's why she has my vote.'","Your credibility is the collateral — spend it on specifics."],"focus":["impact","precision"]},
    {"id":"presence-stu-early-18","level":"early","profession":"student","title":"Observation vs inference at the lab bench","scenario":"In lab discussion you said 'the plant died because the fertilizer was toxic.' Your teacher stops you: what did you OBSERVE? The observation: the fertilized plants browned within a week while controls didn't. Toxicity is your inference.","task":"Restate the finding as 2 sentences: the observation, then the inference marked as inference.","tips":["Observation = what a camera would record.","'One explanation is...' marks inference honestly.","Separating them shows scientific maturity — and survives questioning."],"focus":["precision","clarity"]},
    {"id":"presence-stu-early-19","level":"early","profession":"student","title":"Commit to the essay topic","scenario":"You've been circling three college essay topics for two weeks, asking everyone which they'd pick. Your counselor finally says: you choose, and tell me why. Choosing — and articulating why — is itself the skill being watched.","task":"Write 2 sentences: the topic you're committing to and the reason it beats the other two.","tips":["The reason should be about what only YOU can write, not what sounds impressive.","Naming why the others lose is how you know the choice is real.","A committed mediocre start improves; a hedged perfect plan doesn't exist."],"focus":["clarity","impact"]},
    {"id":"presence-stu-early-20","level":"early","profession":"student","title":"Crossfire without the wince","scenario":"In debate crossfire your opponent asks a question designed to make you concede. Your habit: 'well, I mean, kind of, but...' — agreeing your way into their frame. You can answer directly without being rude.","task":"Write a direct 1-2 sentence crossfire answer that rejects a false premise politely.","tips":["'No — and here's the distinction' is a complete, polite answer.","Name the premise you reject; don't argue inside it.","Calm and direct reads as command; rushed agreement reads as retreat."],"focus":["clarity","impact"],"placeholder":"No — that assumes the ban applies to home games, and it doesn't."},
    {"id":"presence-stu-early-21","level":"early","profession":"student","title":"The peer review with a verdict","scenario":"You're peer-reviewing a classmate's essay and the form asks for an overall assessment. Yours currently reads 'it's pretty good I guess, some parts could maybe be improved.' That helps no one and reads like you didn't try.","task":"Write a 2-3 sentence assessment with a clear verdict, the strongest part, and the one fix that matters most.","tips":["Verdict first: what grade-territory is this draft in and why.","Name the single highest-leverage fix, not six small ones.","Specific praise is as useful as specific criticism."],"focus":["clarity","impact"]},
    {"id":"presence-stu-early-22","level":"early","profession":"student","title":"Recommend the site, run the meeting","scenario":"Your service club is choosing between three volunteer sites for the semester project. You visited all three. At the meeting, you could describe all three neutrally — or you could do what the visits qualified you to do: recommend.","task":"Write your 3-sentence spoken recommendation: pick, reason, and what you'd need from the club.","tips":["You're the only one who visited — neutrality wastes that.","Ground the pick in what you saw, not vibes.","Close with the ask: 'I need eight regulars for Saturdays.'"],"focus":["impact","structure"]},
    {"id":"presence-stu-early-23","level":"early","profession":"student","title":"Two options, one pick","scenario":"Your teacher asked your group to present two possible designs for the class T-shirt and let the class vote. You can present both fairly AND still say which you'd choose — a recommendation with alternatives is stronger than fake neutrality.","task":"Write the 2-3 sentence close of the presentation: both options honored, your pick stated.","tips":["Present both honestly first — that's what earns the right to recommend.","'If it were my call: B, because...' — one reason, said plainly.","The class still votes; your judgment just informs it."],"focus":["clarity","impact"]},
    {"id":"presence-stu-early-24","level":"early","profession":"student","title":"'Why do you want this job?'","scenario":"The bookstore manager will ask why you want the job. The honest-but-weak answer: 'I need money and it's close to my house.' The honest-and-strong answer connects something true about you to something the store needs.","task":"Write a 2-sentence spoken answer that makes a direct claim about fit.","tips":["Direct claim: 'I'd be good at this because...'","True beats polished — pick the real reason that also serves them.","Practice saying it without the rising question-tone at the end."],"focus":["impact","audience"],"placeholder":"I've read forty books this year and I like helping people find the right one —"},
    {"id":"presence-stu-early-25","level":"early","profession":"student","title":"One plank, said like you'll do it","scenario":"Your class-president campaign speech drafts promise eight vague things. Voters remember one committed promise better than eight soft ones. Your real, achievable plank: a monthly student-admin forum you've already discussed with the vice principal.","task":"Write the 2-3 sentence core of the speech: the one plank, signposted, with the proof you can deliver.","tips":["'One promise:' is a signpost that makes ears perk up.","The vice-principal detail is what separates a plan from a wish.","Cut the other seven planks to a single closing clause, or cut them entirely."],"focus":["impact","structure"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-stu-early-01","level":"early","profession":"student","title":"Cold-called in AP History","scenario":"Your teacher cold-calls you: 'Was the New Deal a success?' You know enough to answer, but your habit under pressure is to recite everything you remember about the 1930s and hope an answer emerges. Answer first, then support.","task":"Write the 2-3 sentence spoken answer, verdict first.","tips":["First sentence takes a position — even a qualified one.","Then ONE supporting reason, not the whole chapter.","Rambling reads as not knowing, even when you know."],"focus":["clarity","structure"],"placeholder":"Mostly yes — it didn't end the Depression, but it"},
    {"id":"pressure-stu-early-02","level":"early","profession":"student","title":"The judge's question you can't answer","scenario":"A science fair judge asks how your results would change at different temperatures. You didn't test that and don't know. Bluffing is the one unforgivable move; a blank 'I don't know' wastes the moment. There's a third option.","task":"Write the honest 2-sentence answer: what you don't know, plus how you'd find out.","tips":["'We didn't test that' — say it cleanly, no squirming.","Then show your thinking: what you'd predict and how you'd verify.","Judges score how you think, not just what you know."],"focus":["clarity","impact"],"placeholder":"We didn't test temperature, so I can't say from data. My guess is"},
    {"id":"pressure-stu-early-03","level":"early","profession":"student","title":"Pushback in seminar","scenario":"In Socratic seminar you claimed the poem is about grief, and a classmate counters sharply: 'That's reading way too much into it.' Your face goes hot. The move is not to defend your worth — it's to return to the text with specifics.","task":"Write the 2-sentence spoken reply that answers the challenge with evidence, not defensiveness.","tips":["Respond to the claim, not the tone.","Point at lines: 'Stanza three repeats 'gone' four times.'","'What do you make of that line?' turns a clash into a discussion."],"focus":["precision","impact"]},
    {"id":"pressure-stu-early-04","level":"early","profession":"student","title":"'Why did you leave your last job?'","scenario":"In your interview at the pharmacy, the manager asks why you left the fast-food job. The truth: scheduling clashed with school and the manager kept changing your shifts last-minute. There's a direct, non-bitter way to say it.","task":"Write the 2-sentence spoken answer: direct, factual, no trash talk.","tips":["Answer the actual question first — the reason, plainly.","Facts, not grievances: 'shifts changed with a day's notice.'","Pivot to what you're looking for now, in one clause."],"focus":["clarity","audience"]},
    {"id":"pressure-stu-early-05","level":"early","profession":"student","title":"'Isn't your whole premise wrong?'","scenario":"During Q&A after your presentation on school recycling, a classmate says: 'Doesn't recycling mostly get thrown out anyway, so isn't this whole thing pointless?' Half the class perks up. This is the question your talk lives or dies on.","task":"Write the 2-3 sentence answer: concede what's true, then defend the core with a specific.","tips":["Concede the true part first — it disarms the room.","Then the distinction: what's true of plastic isn't true of aluminum and paper.","End on your strongest number, not a plea."],"focus":["impact","precision"],"placeholder":"You're right that a lot of plastic doesn't get recycled. Aluminum is different:"},
    {"id":"pressure-stu-early-06","level":"early","profession":"student","title":"Coach asks why you missed","scenario":"You missed Tuesday's practice without notice — you genuinely forgot after a schedule change. Coach asks you directly in front of two teammates: 'Where were you?' The excuse spiral makes it worse; the direct answer with ownership ends it.","task":"Write the 2-sentence spoken answer: what happened, ownership, and the fix.","tips":["Answer the question in the first breath: 'I forgot — the schedule change threw me.'","No supporting cast of excuses.","The fix ('it's in my calendar now, it won't repeat') is what coach actually wants."],"focus":["clarity","impact"]},
    {"id":"pressure-stu-early-07","level":"early","profession":"student","title":"The weakness question","scenario":"Your college interviewer asks: 'What's your biggest weakness?' You've heard you should disguise a strength ('I work too hard'). Interviewers have heard that 500 times. A real weakness, named plainly, with real evidence of managing it, is the strong answer.","task":"Write the 2-3 sentence spoken answer: real weakness, real management, no humble-brag.","tips":["Pick something true that isn't disqualifying.","The second sentence — what you DO about it — carries the answer.","Ending with a live example of progress beats claiming it's fixed."],"focus":["clarity","impact"]},
    {"id":"pressure-stu-early-08","level":"early","profession":"student","title":"'Did you do the reading?'","scenario":"Your teacher asks you point-blank in class whether you did last night's reading. You read half. The full-confession ramble and the fake yes are both traps. Precise honesty answers the question and keeps your credibility.","task":"Write the 1-2 sentence honest answer that names exactly what you did and didn't do.","tips":["Exact truth: 'I read the first half, through chapter 9.'","No excuse attached unless asked.","Offer the recovery: 'I'll finish it tonight.'"],"focus":["clarity","precision"],"placeholder":"Half of it — through chapter 9. I'll finish tonight."},
    {"id":"pressure-stu-early-09","level":"early","profession":"student","title":"Cross-ex wants a yes or no","scenario":"In debate cross-examination your opponent demands: 'Yes or no — would your plan cost the district money?' The honest answer is yes, up front, with a cost the plan recovers. Dodging the yes/no looks evasive and burns your time.","task":"Write the spoken answer: the yes/no first, then the one-sentence qualification.","tips":["Give the yes or no in word one — you earn the right to qualify by answering.","One qualification, pre-chosen, delivered calmly.","Evasion loses judges faster than a conceded point does."],"focus":["clarity","structure"],"placeholder":"Yes — about $2,000 up front, which the energy savings repay in"},
    {"id":"pressure-stu-early-10","level":"early","profession":"student","title":"Your data gets challenged","scenario":"Presenting your group's survey results, a classmate interrupts: 'You only asked people at lunch — that's biased.' They're partly right. Getting defensive protects nothing; the specifics of what you did and its limits protect everything.","task":"Write the 2-sentence response: acknowledge the limit precisely, then say what the data still shows.","tips":["Name the limitation more precisely than the challenger did — that takes the sting out.","Then the defensible claim that survives the limit.","'Fair point, and here's what holds' is strength under fire."],"focus":["precision","impact"]},
    {"id":"pressure-stu-early-11","level":"early","profession":"student","title":"The principal asks what happened","scenario":"After a club event left a mess in the gym, the principal stops you — the club president — and asks: 'What happened Saturday?' She asked one question. Your nervous instinct is to answer three she didn't ask and bury the answer she wants.","task":"Write the 2-3 sentence spoken answer to the question actually asked.","tips":["Answer 'what happened' with what happened — sequence, brief.","Own the club's part without volunteering a courtroom defense.","End with the repair already underway."],"focus":["clarity","structure"]},
    {"id":"pressure-stu-early-12","level":"early","profession":"student","title":"'How long will it take you?'","scenario":"Your boss at the restaurant asks how long you need to finish rolling silverware before the dinner rush. You want to say 'not long!' — pleasant, useless. A number lets your boss plan the floor; a vague answer means being asked again in ten minutes.","task":"Write the one-sentence spoken answer with a real number and one condition if needed.","tips":["Give the number you can hit, not the one that sounds impressive.","One condition maximum: 'twenty minutes, if the hostess covers refills.'","Answering with numbers trains people to trust your answers."],"focus":["precision","clarity"]},
    {"id":"pressure-stu-early-13","level":"early","profession":"student","title":"The three-part question","scenario":"At your scholarship interview, a panelist asks: 'Tell us what you'd study, why our program, and what you'd do after.' Three questions in one breath. Answering in a blended blur loses all three; signposting turns it into three easy small answers.","task":"Write the spoken answer's skeleton: a signpost opener plus one sentence per part.","tips":["'Three parts to that —' buys you structure and a beat to think.","Answer in the order asked; the panelist is checking boxes.","Keep part one shortest; people over-spend on the first part."],"focus":["structure","clarity"],"placeholder":"Three parts to that. What I'd study: environmental engineering."},
    {"id":"pressure-stu-early-14","level":"early","profession":"student","title":"The question you don't understand","scenario":"A judge at the history competition asks something long and winding, and you genuinely can't tell what's being asked. Nodding and answering a guessed question wastes everyone's time. Clarifying, done crisply, is a pro move — not an admission of weakness.","task":"Write the 1-2 sentence clarifying response that narrows the question without stalling.","tips":["Offer your best reading: 'Are you asking whether the treaty caused the collapse?'","A specific clarifying guess beats 'can you repeat that?'","One clarification is confident; three is stalling."],"focus":["clarity","audience"]},
    {"id":"pressure-stu-early-15","level":"early","profession":"student","title":"'Tell me about a time you failed'","scenario":"The camp director asks for a time you failed. You have a real one: you overslept and missed your shift's opening during your first month at the pool. The story only works told straight — failure, consequence, change — without softening the failure away.","task":"Write the 3-sentence spoken answer: the failure plainly, the consequence, what changed.","tips":["Name the failure without cushioning — 'I missed my shift' not 'there was a mix-up.'","The consequence sentence proves you understood the impact.","The change should be specific and still true today."],"focus":["clarity","impact"]},
    {"id":"pressure-stu-early-16","level":"early","profession":"student","title":"'Why is this late?'","scenario":"You're handing in your lab report two days late, and your teacher asks why, in the doorway, with the next class filing in. Ten seconds. The full saga is for nobody; the direct answer with ownership takes five seconds and keeps respect.","task":"Write the 1-2 sentence spoken answer.","tips":["Reason in one clause, ownership in the next.","Don't litigate whether the deadline was fair — not now.","Ask the practical question: 'do you still accept it with the penalty?'"],"focus":["concision","clarity"],"placeholder":"I mismanaged my week — no excuse. Does the late policy still apply if"},
    {"id":"pressure-stu-early-17","level":"early","profession":"student","title":"The question outside your project","scenario":"During your capstone Q&A someone asks about a related topic you deliberately excluded from scope. You know a little — enough to be dangerous. The honest bridge: state the boundary, give the little you know as opinion, return to solid ground.","task":"Write the 2-3 sentence answer that manages the scope boundary honestly.","tips":["'That's outside what I studied' is a legitimate, strong answer.","Clearly mark speculation as speculation if you offer any.","Bridge back: 'what my data DOES show is...'"],"focus":["clarity","precision"]},
    {"id":"pressure-stu-early-18","level":"early","profession":"student","title":"The cost objection you saw coming","scenario":"You proposed a school composting program to student council, and the predictable pushback lands: 'Sounds expensive.' You prepared for exactly this: $180 in bins, offset by the district's per-bag trash pickup fees within one semester.","task":"Write the 2-sentence spoken response deploying the numbers you prepared.","tips":["Meet the objection with the number, not with re-explaining the vision.","Show the offset: cost next to savings, same sentence.","Calm specificity converts skeptics; enthusiasm alone entrenches them."],"focus":["precision","impact"],"placeholder":"$180 total, for the bins. The district charges us per trash bag, so"},
    {"id":"pressure-stu-early-19","level":"early","profession":"student","title":"'What's your source for that?'","scenario":"In class discussion you cited a statistic about teen screen time, and your teacher asks, in front of everyone: 'Where's that from?' You read it somewhere real but can't place it. Fabricating a source is the disaster; honest precision about your uncertainty is fine.","task":"Write the 1-2 sentence honest answer.","tips":["Say exactly what you're sure of and what you're not.","Offer the follow-up: 'I'll find the source and post it.'","A citation you can't produce yet is a claim on hold — treat it that way aloud."],"focus":["precision","clarity"]},
    {"id":"pressure-stu-early-20","level":"early","profession":"student","title":"Called out in the group chat","scenario":"A group member posts, publicly: 'we're still waiting on YOUR section, everyone else finished days ago.' It stings, and it's basically true. Twenty classmates can see the thread. The reply that ends it: no counterattack, a fact, a time.","task":"Write the 1-2 sentence reply that answers the challenge and closes the thread.","tips":["Don't relitigate why — give the delivery time.","A specific timestamp beats 'almost done.'","One reply, then deliver; the work is the comeback."],"focus":["clarity","impact"],"placeholder":"Fair. Draft's at 80% — full section in the doc by 9 tonight."},
    {"id":"pressure-stu-early-21","level":"early","profession":"student","title":"Rapid-fire round","scenario":"The scholarship panel ends with quick questions: 'Favorite subject?' 'A book that changed you?' 'One word your friends use for you?' You tend to give ninety-second answers to nine-second questions, and the panel starts glancing at the clock.","task":"Write one-sentence answers to all three questions.","tips":["Match the answer's size to the question's size.","One concrete detail each — 'chemistry, because of the day we...' is already too long. Trim.","Quick answers with texture beat slow answers with everything."],"focus":["concision","impact"]},
    {"id":"pressure-stu-early-22","level":"early","profession":"student","title":"Your interpretation vs the teacher's","scenario":"Your English teacher, grading aloud, questions your essay's claim that the narrator forgives her mother. You still think you're right — and there's a line in the final scene where she uses her mother's recipe unprompted. Push back requires text, not volume.","task":"Write the 2-sentence spoken reply that defends the reading with the textual moment.","tips":["Respect the doubt, then present the line.","Explain what the detail does: 'cooking her recipe is the forgiveness.'","Teachers grade up when pushback comes with evidence."],"focus":["precision","impact"]},
    {"id":"pressure-stu-early-23","level":"early","profession":"student","title":"'I don't know' with a path","scenario":"In calculus the teacher asks you to start problem 6 at the board. You look at it and genuinely don't know the second step. Freezing silently and guessing randomly both burn the moment. Naming what you DO know creates a path.","task":"Write the 1-2 sentence spoken response that admits the gap and starts the path.","tips":["'I can set it up; I get stuck at the substitution' — the precise gap invites precise help.","Showing your partial thinking teaches the class more than a silent freeze.","'I don't know YET, here's my first move' keeps you in the problem."],"focus":["clarity","structure"],"placeholder":"I can get the first step — factor out the 2x. Where I'm stuck is"},
    {"id":"pressure-stu-early-24","level":"early","profession":"student","title":"The unhappy customer","scenario":"At your register a customer says, loudly: 'You charged me twice — this is ridiculous.' Whether or not it's true yet, the pressure is real and public. Their actual question is 'will you fix this?' Answer that one first.","task":"Write the 1-2 sentence spoken response: address the fix first, no defensiveness.","tips":["First words commit to resolving it: 'Let me check that right now.'","Don't argue the charge before looking — verify, then speak.","Calm scripts survive pressure; improvised defenses escalate it."],"focus":["audience","clarity"]},
    {"id":"pressure-stu-early-25","level":"early","profession":"student","title":"The loaded question at the forum","scenario":"At the student-council candidate forum someone asks: 'Why does council always waste money on dances nobody likes?' It's loaded — 'always,' 'waste,' 'nobody.' Attacking the loading looks defensive; answering the fair core looks like leadership.","task":"Write the 2-3 sentence answer that extracts and answers the fair question inside the loaded one.","tips":["Restate the fair core: 'The real question is whether dance spending matches what students want.'","Answer THAT with a fact and a commitment.","Never repeat the hostile framing — replace it."],"focus":["impact","structure"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-stu-early-01","level":"early","profession":"student","title":"The essay that shows a change","scenario":"Your college essay describes volunteering at a food bank, but it reads like a job description: tasks, hours, duties. What admissions actually reads for: who you were before, what happened, who you are after. The change is the story.","task":"Write 2-3 sentences sketching the before/after arc your essay should follow.","tips":["Name the specific belief or habit you started with.","One scene where it shifted — a person, a moment, not a summary.","The 'after' should be visible in something you do differently now."],"focus":["structure","impact"],"placeholder":"Before: I thought hunger was a statistic. Then a classmate came through the line."},
    {"id":"narrative-stu-early-02","level":"early","profession":"student","title":"The new-club pitch to the principal","scenario":"You want to start a personal-finance club. Your draft pitch to the principal lists activities. What's missing: the stakes (seniors graduate without knowing what a credit score is) and the before/after (what changes for students who join).","task":"Write a 3-4 sentence pitch with concrete stakes and a clear after-picture.","tips":["Open with the problem made concrete — one real scenario, not 'financial literacy matters.'","Paint the after: what a member can DO by June.","Pre-empt the obvious objection: no budget needed, you have an advisor lined up."],"focus":["impact","audience"]},
    {"id":"narrative-stu-early-03","level":"early","profession":"student","title":"Paint the Tuesday after you win","scenario":"Your campaign speech lists qualities: dedicated, experienced, approachable. Voters can't picture qualities. They can picture a Tuesday: what actually changes at school if you win — the thing they'll see, touch, or stop being annoyed by.","task":"Write the 2-3 sentence section of the speech that paints the specific 'after.'","tips":["Pick one visible change and describe the experience of it.","'Imagine checking one app instead of four' beats 'better communication.'","Concrete futures are memorable; adjectives evaporate by lunch."],"focus":["impact","audience"],"placeholder":"Next semester, you check one calendar and every club's events are on it."},
    {"id":"narrative-stu-early-04","level":"early","profession":"student","title":"Stakes for the op-ed","scenario":"Your school-paper op-ed argues the library's shortened hours hurt students. Your draft says access to resources is important. Nobody disagrees, and nobody acts on 'important.' The stakes live in specifics: who, exactly, loses what, exactly.","task":"Write the 2-3 sentence stakes paragraph naming a specific kind of student and their specific loss.","tips":["Trade the abstract ('access') for a person ('a junior whose only quiet wifi is here until her shift').","Numbers help: how many students, how many hours lost.","The reader should feel the cost before you propose anything."],"focus":["impact","precision"]},
    {"id":"narrative-stu-early-05","level":"early","profession":"student","title":"Selling the morning practice","scenario":"You want your club soccer team to move one practice to 6:30am to get field time. You know exactly what they'll say: mornings are brutal. Pretending mornings aren't brutal will lose them. Naming the objection first, then beating it, might not.","task":"Write the 3-sentence pitch that raises the objection yourself and answers it.","tips":["Say their objection better than they would — it builds trust instantly.","Then the trade: what the field time buys that afternoon practice can't.","End with a trial frame: 'three weeks, then we vote again.'"],"focus":["impact","structure"],"placeholder":"I know — 6:30am is miserable. Here's what we get for it:"},
    {"id":"narrative-stu-early-06","level":"early","profession":"student","title":"The pitch to the pizza shop","scenario":"You're asking a local pizza shop to sponsor your team's tournament shirts for $150. Your draft talks about how much the team needs money. The owner hears requests like this weekly. What works: what the owner's $150 buys THEM.","task":"Write the 3-sentence ask framed around the shop's before/after, not the team's need.","tips":["The story is theirs: their logo, seen by whom, how many times.","Make the after concrete: '200 families at the tournament, logo on 18 shirts all season.'","One sentence of team warmth, then the business case."],"focus":["audience","impact"]},
    {"id":"narrative-stu-early-07","level":"early","profession":"student","title":"Recruiting your friend to robotics","scenario":"Your friend is on the fence about joining robotics. You've been listing features: meetings, competitions, the cool equipment. Features aren't moving them. What might: the before/after of someone exactly like them — maybe literally you, a year ago.","task":"Write the 2-3 sentence personal pitch built on a before/after they can see themselves in.","tips":["Start where they are: 'You like building things and hate joining things.'","Your own arc is evidence: what changed for you in a semester.","Invite them to one specific low-commitment thing, not 'the club.'"],"focus":["audience","impact"]},
    {"id":"narrative-stu-early-08","level":"early","profession":"student","title":"The petition's strongest enemy","scenario":"Your petition for a later school start time is gathering signatures, and you're writing its core paragraph. The strongest counterargument isn't laziness — it's bus schedules and parent work logistics. If your petition ignores that, the district's first reply kills it.","task":"Write 2-3 sentences that pre-empt the logistics objection before making your ask.","tips":["Name the real obstacle yourself — it shows you did the homework.","Point to a district that solved it, or propose the study that would.","A pre-empted objection becomes your credibility; an ignored one becomes your obituary."],"focus":["structure","impact"]},
    {"id":"narrative-stu-early-09","level":"early","profession":"student","title":"The obstacle essay without the violin","scenario":"The scholarship prompt asks about overcoming an obstacle. Your draft describes six months of struggle in detail and mentions what changed in one final line. Readers don't award struggle; they award what you built from it. Rebalance toward the turn.","task":"Write the 2-3 sentence 'turn' — the moment things changed and what you did next.","tips":["The turn is an action you took, not a thing that happened to you.","Give the recovery as much space as the fall.","Resist the misery competition; specificity beats severity."],"focus":["structure","impact"]},
    {"id":"narrative-stu-early-10","level":"early","profession":"student","title":"The podcast instead of the paper","scenario":"You want your teacher to let you submit a podcast episode instead of the assigned essay. Teachers hear 'can I do something easier?' in every such request. Your persuasion has to prove the opposite: same rigor, same evidence, plus a skill the essay can't show.","task":"Write the 3-sentence request that pre-empts the 'easier' suspicion directly.","tips":["Name the suspicion: 'This isn't a workaround —' and prove it with your plan.","Map podcast elements to the rubric one-to-one.","Offer the safeguard: script submitted with the audio."],"focus":["audience","structure"],"placeholder":"I'd like to propose the podcast format — with the same thesis, sources, and a full script submitted."},
    {"id":"narrative-stu-early-11","level":"early","profession":"student","title":"Service hours with stakes","scenario":"Your honor society application asks why your service mattered. Your draft: 'I volunteered 40 hours at the community garden.' Hours are inputs. The story is what existed afterward that didn't before — and for whom.","task":"Write 2-3 sentences that convert the hours into a before/after for the people served.","tips":["What did the 40 hours produce? Count it: beds built, pounds grown, families served.","One named-scale detail ('the Tuesday food pantry') grounds it.","You're a character in the story, not the point of it."],"focus":["impact","precision"]},
    {"id":"narrative-stu-early-12","level":"early","profession":"student","title":"The booster club ask","scenario":"You're the team rep asking the parents' booster club to fund $400 in tournament travel. Parents fund outcomes for kids, not line items. Your draft has the budget; it's missing the story — what this tournament is in the arc of the team's season.","task":"Write the 3-sentence ask that wraps the $400 in the season's narrative.","tips":["Situate the moment: 'For the first time in four years, we qualified.'","Then the gap: qualified, but the venue is 200 miles away.","The ask lands as the resolution: '$400 puts all 12 players there.'"],"focus":["impact","structure"],"placeholder":"For the first time in four years, the team qualified for state."},
    {"id":"narrative-stu-early-13","level":"early","profession":"student","title":"Recycling without the sermon","scenario":"You're giving a two-minute assembly announcement about the new recycling program. The preachy version — 'we all must do our part for the planet' — triggers instant tune-out. Concrete, local, surprising stakes might survive: what your school threw away last month alone.","task":"Write the 2-3 sentence opening with local, concrete stakes and zero preaching.","tips":["Local numbers beat global doom: this school, last month.","Surprise is the hook: pick the stat people will repeat at lunch.","Ask for one behavior, not a worldview."],"focus":["impact","audience"],"placeholder":"Last month our school threw away 1,100 plastic bottles. They were all"},
    {"id":"narrative-stu-early-14","level":"early","profession":"student","title":"Recruiting tutors with a story","scenario":"Your peer-tutoring program needs 10 new volunteer tutors. The flyer says 'looks great on college apps!' — which recruits people who quit in three weeks. The recruits who stay come for a different story: the one where a specific kid finally gets it.","task":"Write the 2-3 sentence recruitment pitch built around one small true story.","tips":["One tutoring moment, told concretely, is the whole pitch.","Let the reward be the visible one: the kid's face when the math clicks.","College-app benefit can be the last clause, not the headline."],"focus":["impact","audience"]},
    {"id":"narrative-stu-early-15","level":"early","profession":"student","title":"The yearbook theme pitch","scenario":"You're pitching this year's yearbook theme to the staff: 'Under Construction' — the school spent the year half-renovated, classes in trailers, everything temporary. The pitch needs to sell the theme as the story of THIS year, not just a cute title.","task":"Write the 3-sentence pitch connecting the theme to the year everyone actually lived.","tips":["Tie the theme to shared experiences everyone will recognize.","Show its range: it covers the building AND the students becoming something.","A theme pitch is a narrative claim: 'this is what this year was about.'"],"focus":["impact","structure"]},
    {"id":"narrative-stu-early-16","level":"early","profession":"student","title":"Restart the project, eat the sunk cost","scenario":"Three weeks into your group's history project, you've realized the approach can't work — the sources don't exist. Your group's objection is inevitable: 'we already did so much.' The persuasion must reframe: the three weeks aren't wasted, but the next three might be.","task":"Write the 3-sentence case for restarting that defuses the sunk-cost objection.","tips":["Honor the work: name what transfers to the new approach.","The real comparison is future vs future, not past vs future.","Concrete deadline math: what's finishable by the due date on each path."],"focus":["structure","impact"],"placeholder":"Everything we learned transfers — the research skills, half the sources. What doesn't work is"},
    {"id":"narrative-stu-early-17","level":"early","profession":"student","title":"The slot-trade favor","scenario":"You need to swap presentation slots with a classmate — you present Monday, you want their Thursday. Taking your Monday slot costs them three prep days, so for them the swap is pure inconvenience unless you offer something real in return.","task":"Write the 2-sentence trade proposal that offers them something real.","tips":["Find the genuine trade: your prep notes, your slot next round, help with their setup.","Name their cost honestly — pretending it's costless insults them.","A fair trade framed as a trade beats a favor framed as nothing."],"focus":["audience","impact"]},
    {"id":"narrative-stu-early-18","level":"early","profession":"student","title":"No experience, reframed","scenario":"The application asks about relevant experience, and you've never had a job. Listing nothing is wrong; apologizing is worse. The reframe: you have three years of showing up — team practices, club deadlines, group projects — which is the job skill they're actually screening for.","task":"Write the 2-3 sentence answer that reframes school commitments as the evidence they need.","tips":["Name the underlying skill they want: reliability, coachability, teamwork.","Then your proof: three seasons, zero missed practices, specific responsibilities.","Never open with 'although I have no experience' — open with what you have."],"focus":["audience","impact"],"placeholder":"Three seasons on the swim team taught me the thing schedules test:"},
    {"id":"narrative-stu-early-19","level":"early","profession":"student","title":"Thirty seconds at the club fair","scenario":"Freshmen drift past your booth in a noisy gym. You have thirty seconds when one pauses. The pitch that works is a miniature story with them as the hero — where they start, what happens, where they end up by spring — not a list of meeting logistics.","task":"Write the 30-second (2-3 sentence) spoken pitch with the freshman as protagonist.","tips":["Second person, future tense: 'You'll walk in knowing nobody; by March you'll...'","One concrete milestone they can picture reaching.","End with the tiny next step: name on the list, come Thursday."],"focus":["audience","impact"]},
    {"id":"narrative-stu-early-20","level":"early","profession":"student","title":"Save the art program","scenario":"Budget cuts threaten the ceramics elective, and you're speaking at the school board's public comment session. The board's constraint is real: money. Emotion alone bounces off a spreadsheet. Your two minutes need stakes the board can weigh AND the objection handled.","task":"Write the 3-sentence core: concrete stakes, the budget objection named, your answer to it.","tips":["Stakes in board terms: enrollment, the 60 students with no other arts credit option.","Name the number they're weighing, then show the smaller true cost.","One student's specific story as the closer, not the opener."],"focus":["impact","precision"]},
    {"id":"narrative-stu-early-21","level":"early","profession":"student","title":"The crosswalk letter","scenario":"You're writing to the town paper about the intersection by the school where you cross daily: two near-misses you've personally seen this semester. The letter needs the town to feel the stakes in their stomach, then hand them a specific, cheap fix.","task":"Write the 2-3 sentence core of the letter: the scene, the stakes, the fix.","tips":["Open in the scene: the specific corner, the specific morning.","Near-miss details do the persuading — let them.","The ask should be small and concrete: a crossing guard, a repainted crosswalk, a sign."],"focus":["impact","precision"],"placeholder":"On the corner of 5th and Maple, at 7:40 most mornings,"},
    {"id":"narrative-stu-early-22","level":"early","profession":"student","title":"Change the study method before finals","scenario":"Your study group rereads notes together — comfortable, familiar, and (you've learned) nearly useless. You want to switch to practice testing. The group's unspoken objection: rereading feels good and quizzing feels like failing. Your pitch has to make the discomfort the point.","task":"Write the 2-3 sentence pitch that pre-empts 'but quizzing feels worse' and proposes a trial.","tips":["Reframe the discomfort: feeling bad during practice is the studying working.","One concrete comparison: last test's results vs how prepared everyone felt.","Propose one session as an experiment — small yes first."],"focus":["impact","structure"]},
    {"id":"narrative-stu-early-23","level":"early","profession":"student","title":"The community grant application","scenario":"A local foundation gives $500 grants to youth projects. Your club wants it for a little free pantry. The application's key question: 'What will be different because of this grant?' — a literal before/after prompt. Your draft describes the pantry; it should describe the difference.","task":"Write the 3-sentence answer: before (now), after (with the grant), and who feels the change.","tips":["Before: the current gap, in one concrete image.","After: the pantry stocked, where, serving roughly whom, how often.","Foundations fund differences, not objects — write the difference."],"focus":["structure","precision"],"placeholder":"Right now, the nearest food support is a bus ride away. With this grant,"},
    {"id":"narrative-stu-early-24","level":"early","profession":"student","title":"'We've always done it this way'","scenario":"You want your coach to try a new warm-up routine you learned at summer camp. Coaches hear player suggestions constantly, and the standing objection is tradition: the current routine has worked for years. Your pitch needs respect for the old, evidence for the new, and a tiny ask.","task":"Write the 2-3 sentence pitch that honors the tradition and still lands the trial.","tips":["Lead by crediting what works — you're adding, not overthrowing.","One piece of evidence: where you saw it work, on whom.","Shrink the ask: ten minutes, one practice, coach judges the result."],"focus":["audience","impact"]},
    {"id":"narrative-stu-early-25","level":"early","profession":"student","title":"Start in the moment","scenario":"Your personal statement opens: 'Ever since I was young, I have always been passionate about helping others.' Admissions readers see that sentence hundreds of times a season. Somewhere in your draft's third paragraph is an actual moment — you, mid-action, the day it got real.","task":"Write the replacement opening: 1-2 sentences that begin inside that moment.","tips":["Start mid-scene: what you were doing, seeing, holding.","Cut every 'always' and 'passionate' — the scene proves what they claim.","If your opener could begin anyone's essay, it can't begin yours."],"focus":["impact","clarity"],"placeholder":"The kid across the table erased his answer for the fourth time, and"}
  ],
  "delivering-hard-messages": [
    {"id":"hard-stu-early-01","level":"early","profession":"student","title":"Behind on your part","scenario":"The group project is due Friday and your section — the one everyone's parts connect to — is two days behind. Every hour you delay saying so, their options shrink. The message you're avoiding is exactly the one they need now, bad news first.","task":"Write the 2-3 sentence group message: the news up front, the realistic new time, one ask.","tips":["Sentence one is the news: 'My section is behind — realistic delivery is Thursday morning.'","No excuse paragraph; one clause of reason at most.","Give them something actionable: what they can do in parallel."],"focus":["clarity","impact"],"placeholder":"My section is running two days behind — realistic delivery is Thursday 8am."},
    {"id":"hard-stu-early-02","level":"early","profession":"student","title":"The clean no to a friend","scenario":"Your friend asks to copy your chemistry homework — again. Last time you said 'I don't know, maybe later' and they wore you down. A clean no is kinder than a soft maybe that breeds three more asks. You can refuse the copying and still offer something real.","task":"Write the 1-2 sentence spoken no with one genuine alternative.","tips":["'No' plus a reason you can repeat: it's not worth the risk to either of us.","The alternative should cost you something small: twenty minutes of explaining, not the answers.","A no without wobble ends the negotiation kindly."],"focus":["clarity","impact"]},
    {"id":"hard-stu-early-03","level":"early","profession":"student","title":"Stepping down as president","scenario":"Between AP courses and your job, you can't keep leading the volunteer club, and you've decided to step down at semester. The club deserves to hear it early and plainly — not through rumor, not padded with three paragraphs of guilt.","task":"Write the 3-sentence announcement: the decision first, the timing, and the transition plan.","tips":["Decision in sentence one, unhedged: 'I'm stepping down as president at semester.'","Skip the guilt spiral — one sentence of why is plenty.","The transition plan is the real gift: who, when, how."],"focus":["clarity","structure"],"placeholder":"I'm stepping down as president at the end of the semester."},
    {"id":"hard-stu-early-04","level":"early","profession":"student","title":"Telling coach you're done","scenario":"After three seasons, you're quitting track to focus on your senior year workload. Coach invested in you, and you've been dreading the conversation — which is why you owe it face-to-face and front-loaded, not mumbled sideways or sent by text at 11pm.","task":"Write the 2-3 sentence spoken opening for the conversation.","tips":["Front-load: 'I've decided not to run this season.' Then breathe.","Gratitude belongs in the message — after the news, not disguising it.","Decided means decided: don't leave a thread to tug that reopens it."],"focus":["clarity","impact"]},
    {"id":"hard-stu-early-05","level":"early","profession":"student","title":"Quitting the job for school","scenario":"Junior year has swallowed your schedule and you need to leave your cafe job. Your manager took a chance on you at fifteen. The hard message done right: the news, the notice period, and what you'll do to make the handoff easy — all in the first breath.","task":"Write the 3-sentence resignation message: news, last date, handoff offer.","tips":["News and date in sentence one — the manager's mind goes straight to scheduling.","Two weeks' notice, stated as a date, not 'soon.'","Offering to help train your replacement is the professional exit."],"focus":["clarity","structure"],"placeholder":"I need to give my two weeks' notice — my last shift would be the 21st."},
    {"id":"hard-stu-early-06","level":"early","profession":"student","title":"The teammate who keeps missing","scenario":"Your project teammate has missed two of three work sessions, and their absence pushed work onto everyone else. You're the one who talks to them. The formula that stays fair under stress: the behavior (factual), the impact (concrete), the ask (specific).","task":"Write the 3-sentence message: behavior, impact, ask — no character judgments.","tips":["Behavior: 'you missed Tuesday and Thursday' — dates, not 'you always.'","Impact: who absorbed the work, what it cost.","Ask: the specific commitment for the remaining sessions."],"focus":["clarity","structure"],"placeholder":"You missed Tuesday's and Thursday's sessions, and Maya and I split your slides both times."},
    {"id":"hard-stu-early-07","level":"early","profession":"student","title":"Your friend's speech has a problem","scenario":"Your best friend runs their student-council speech by you the night before. It's likable — and it has a serious problem: the centerpiece joke lands on a classmate who'll be in the audience. Telling them tonight is a favor; letting them find out on stage is not.","task":"Write the 2-3 sentence spoken feedback: the problem named plainly, why it matters, the fix.","tips":["Don't bury it under compliments they'll remember instead.","Name the specific risk: how that joke lands for that classmate and the room.","Come with the fix: what to swap in — the speech survives without it."],"focus":["clarity","audience"]},
    {"id":"hard-stu-early-08","level":"early","profession":"student","title":"The fundraiser lost money","scenario":"You organized the club's movie night, and after venue and licensing costs it LOST $40. The advisor is expecting a deposit. The report you're avoiding is three sentences long: the number, the cause, and what next event does differently.","task":"Write the 3-sentence report with the loss in sentence one.","tips":["The number first — hearing it from you beats her finding it in the ledger.","One-sentence diagnosis: the licensing fee you didn't know about.","The 'next time' sentence turns a loss into tuition."],"focus":["clarity","precision"],"placeholder":"Movie night lost $40: the film licensing fee was $150, which"},
    {"id":"hard-stu-early-09","level":"early","profession":"student","title":"Declining to lead","scenario":"The advisor asked you to chair the spring charity drive — a big honor, and you're already at capacity. Saying yes and doing it badly would hurt the drive. The no needs to be prompt, clear, and warm, possibly with a smaller yes inside it.","task":"Write the 2-3 sentence decline.","tips":["Thank, then decline in the same breath — don't make them read to the end hoping.","No inflated excuses; 'I can't give it the time it needs' is complete.","The smaller yes (one committee, one event) is optional but gracious."],"focus":["clarity","audience"]},
    {"id":"hard-stu-early-10","level":"early","profession":"student","title":"You broke the beaker rack","scenario":"Cleaning up after chemistry, you knocked over and broke a rack of beakers. Nobody saw. The teacher will notice Monday. Reporting it now — plainly, with an offer to make it right — is a five-sentence conversation; being discovered later is a semester of doubt.","task":"Write the 2-sentence confession: what happened, and your offer to make it right.","tips":["Plain report: what broke, how — no minimizing, no melodrama.","The offer matters: replace them, stay after to help inventory.","Fast and direct converts a mistake into credibility."],"focus":["clarity","impact"],"placeholder":"I knocked over the beaker rack while cleaning up — six broke."},
    {"id":"hard-stu-early-11","level":"early","profession":"student","title":"The section that needs a rewrite","scenario":"Your groupmate submitted their project section and it's not usable — off-topic and missing the required sources. The deadline leaves time to fix it, barely, if you tell them today. 'It's fine, I'll just redo it myself' is the lie that poisons groups.","task":"Write the 2-3 sentence message: the problem specifically, the standard it needs to meet, the offer to help.","tips":["Point at the gap, not the person: 'it covers X, but the rubric asks for Y.'","Attach the rubric line — external standards depersonalize.","Offer partnership on the fix, not a takeover."],"focus":["clarity","structure"]},
    {"id":"hard-stu-early-12","level":"early","profession":"student","title":"Declining the nomination","scenario":"A friend nominated you for club treasurer, and the room is looking at you. You don't want it — you know your semester can't hold it. Declining on the spot, kindly and without a wobble, spares everyone a resignation in October.","task":"Write the 1-2 sentence spoken decline you'd say in the meeting.","tips":["Gratitude and decline in one motion: 'I'm honored, and I have to say no.'","One true reason, briefly — overloaded schedules need no apology.","Suggest nothing you don't mean; endorse someone else only if it's genuine."],"focus":["clarity","concision"]},
    {"id":"hard-stu-early-13","level":"early","profession":"student","title":"The lineup change conversation","scenario":"As co-captain you agreed with coach: your friend moves from starter to rotation for Friday's game. She'll hear it either from the posted lineup or from you first. From you first, done plainly, is the version your friendship survives.","task":"Write the 2-3 sentence spoken message: the change first, the reason honestly, no false promises.","tips":["The change in sentence one — she knows why you pulled her aside.","The real reason, respectfully: matchups, practice numbers — not 'coach just decided.'","Don't promise she'll start next week unless it's yours to promise."],"focus":["clarity","impact"]},
    {"id":"hard-stu-early-14","level":"early","profession":"student","title":"You forgot to submit for everyone","scenario":"You were the one submitting the group's assignment portal upload, and you forgot. It's now six hours late; the penalty is shared. The group finds out either from the gradebook or from you, right now, with the news first and the fix attempted.","task":"Write the 2-3 sentence group message.","tips":["News first, ownership immediate: 'I forgot to submit — this is on me.'","State what you've already done: emailed the teacher, asked about the penalty.","Absorb what you can: offer to take the point hit if the teacher allows it."],"focus":["clarity","impact"],"placeholder":"I forgot to submit our project last night — it's on me, and I've already emailed Ms. Alvarez."},
    {"id":"hard-stu-early-15","level":"early","profession":"student","title":"The shift-cover pattern","scenario":"The same coworker has asked you to cover their weekend shift four times this month, and you've said yes every time. Your grades are slipping and you're done — but 'sorry, I can't this once' invites ask number five. The message has to name the pattern.","task":"Write the 2-sentence message that declines this ask and closes the pattern.","tips":["Decline the instance and name the pattern in the same message.","'I can't keep covering weekends' draws the line; no essay needed.","Hold the goodwill: one sincere line, zero new loopholes."],"focus":["clarity","impact"],"placeholder":"I can't take this Saturday — and I need to stop being the regular cover for weekends."},
    {"id":"hard-stu-early-16","level":"early","profession":"student","title":"The missed printer deadline","scenario":"You're the yearbook layout editor, and the senior-section proofs missed the printer's deadline — which means either a rush fee or the book ships a week late. The staff meeting is tomorrow, and the news should open it, not leak out mid-agenda.","task":"Write the 2-3 sentence announcement: the miss, the two options with costs, the decision needed.","tips":["Front-load the miss and its consequence — no warm-up slides.","Present both options with real numbers; the group decides with you.","What caused it gets ONE sentence, and only after the options."],"focus":["clarity","structure"]},
    {"id":"hard-stu-early-17","level":"early","profession":"student","title":"The trip is canceled","scenario":"The regional competition trip your club fundraised for all semester is canceled — not enough chaperones cleared in time. You're the president, and 20 members find out from your message. The bad news needs to come first; the salvage plan needs to come second, not never.","task":"Write the 3-sentence announcement: the cancellation, the honest reason, what happens to the money and the season.","tips":["Cancellation in sentence one — subject lines and first lines carry the weight.","The reason, honestly, without assigning public blame.","Answer the two questions they'll all have: the funds, and what's next."],"focus":["clarity","structure"],"placeholder":"The regionals trip is canceled — we couldn't get enough cleared chaperones in time."},
    {"id":"hard-stu-early-18","level":"early","profession":"student","title":"Asking for the partner reset","scenario":"Your assigned lab partnership isn't working: you've done the last three writeups alone after agreeing on splits. You've decided to ask the teacher to intervene. Framing it as facts-plus-request keeps it from sounding like tattling — which is what you're afraid of.","task":"Write the 2-3 sentence request to the teacher: the facts, what you've tried, the specific help you want.","tips":["Dates and artifacts, not character: 'the last three writeups' is checkable.","Show your attempt first: the conversation you already had.","Ask for a specific intervention: a check-in, a re-pairing, a split grade."],"focus":["clarity","precision"]},
    {"id":"hard-stu-early-19","level":"early","profession":"student","title":"No to the teacher who counts on you","scenario":"Your favorite teacher asks you to also run the freshman mentoring table at orientation — on top of the two things you already do for her. She asks because you always say yes. This time the true answer is no, and it needs to survive her disappointment.","task":"Write the 2-sentence spoken decline that protects both the no and the relationship.","tips":["Decline the task, affirm the relationship: both in two sentences.","A capacity reason is honorable — name what you're protecting (your two current commitments).","Don't manufacture a fake conflict; real reasons repeat better."],"focus":["clarity","audience"]},
    {"id":"hard-stu-early-20","level":"early","profession":"student","title":"The mentee who derailed the meeting","scenario":"The freshman you mentor took over yesterday's club meeting — interrupting, joking over the treasurer, derailing the vote. Others noticed and looked at you. The feedback conversation is yours to have: behavior, impact, ask, delivered like a peer, not a scolding parent.","task":"Write the 3-sentence spoken feedback using behavior-impact-ask.","tips":["Behaviors are quotable: 'you talked over Jordan twice during the vote.'","Impact includes them: how the room read it, what it costs their standing.","The ask is forward-looking and small: one meeting, one changed behavior."],"focus":["clarity","structure"]},
    {"id":"hard-stu-early-21","level":"early","profession":"student","title":"Postponing the parents' event","scenario":"The family potluck your club planned has to move — the cafeteria got double-booked for a district event. Thirty families RSVPed, some arranged work schedules around it. The email needs the change up top and the new details unmissable.","task":"Write the 3-sentence email: the postponement and new date first, the apology brief, the logistics exact.","tips":["Subject and first line carry the change — assume some read nothing else.","One clean apology sentence; over-apologizing makes it about you.","Restate ALL logistics fresh: date, time, place — don't make anyone merge two emails."],"focus":["clarity","audience"],"placeholder":"The family potluck is moving to Thursday, May 8, same time (6pm) — the cafeteria was double-booked."},
    {"id":"hard-stu-early-22","level":"early","profession":"student","title":"Correcting your own announcement","scenario":"Yesterday you announced auditions for Saturday at 10am — to the whole school, over the PA. They're actually at 9am. Some students will plan around your mistake. The correction has to be louder than the error and own it without a paragraph of self-flagellation.","task":"Write the 2-sentence correction announcement.","tips":["Correction first: the RIGHT time, stated twice if the channel allows.","'I gave the wrong time yesterday' — plain ownership, four words of it.","Push the correction through every channel the error traveled."],"focus":["clarity","concision"],"placeholder":"Correction: auditions are Saturday at 9am, not 10 —"},
    {"id":"hard-stu-early-23","level":"early","profession":"student","title":"Reporting the score error","scenario":"Reviewing the meet results as team statistician, you found a scoring error — in your team's favor. Correcting it likely drops your team from 2nd to 3rd. You have to tell your coach before you tell the league. The message needs the finding, the consequence, and no apology for honesty.","task":"Write the 2-3 sentence message to your coach.","tips":["Finding first, plainly: which event, which number, what the correction is.","Name the consequence honestly — coach hears it from you, once.","You're not apologizing for integrity; skip 'I hate to do this.'"],"focus":["clarity","precision"]},
    {"id":"hard-stu-early-24","level":"early","profession":"student","title":"Leaving your debate partner","scenario":"After two years as partners, you're switching to a solo event next season. Your partner will hear it as a breakup, and there's no framing that makes it painless — only framings that are honest and prompt versus evasive and late. You're telling them this week, in person.","task":"Write the 2-3 sentence spoken opening: the decision, the true reason, what stays.","tips":["The decision arrives in sentence one, decided — not floated for debate.","The true reason (the event, not the person) said once, cleanly.","Name what's real and stays: the two years, the friendship, this season's finish."],"focus":["clarity","impact"]},
    {"id":"hard-stu-early-25","level":"early","profession":"student","title":"Leaving the study group","scenario":"The Sunday study group has become three hours of socializing, and your grades need the time back. These are your friends. The exit message should be clean — the decision, a true reason without indicting anyone, and the friendship explicitly kept.","task":"Write the 2-sentence exit message to the group chat.","tips":["Decide, don't hint: 'I'm going to study solo this quarter.'","Make the reason about your needs, not their behavior.","Close the right door only: leaving the group, not the friend group."],"focus":["clarity","concision"],"placeholder":"I'm switching to studying solo this quarter — I focus better alone, and my calc grade needs it."}
  ],
  "putting-it-together": [
    {"id":"together-stu-early-01","level":"early","profession":"student","title":"Same news, two channels","scenario":"Practice is canceled Thursday. You have to tell your coach's boss — the athletic director — by email, and your teammates in the group chat. Same fact, two completely different registers: one formal and complete, one instant and unmissable.","task":"Write both: the 2-sentence email to the AD and the 1-line group chat message.","tips":["The email carries context and copies the record; the chat carries speed.","Same core fact in both — never let the versions drift.","Match formality to reader, not to your mood."],"focus":["audience","clarity"]},
    {"id":"together-stu-early-02","level":"early","profession":"student","title":"The stranger test","scenario":"Your college essay is 'done.' Now read it as its real reader will: a stranger, at essay #40 of the evening, who knows nothing about you. Where does a stranger stumble? What does paragraph two assume that was never said? Which sentence exists because YOU like it?","task":"List the 3 reader-side checks you'd run and what each would catch in a typical draft.","tips":["Check one: can a stranger say what the essay is about after paragraph one?","Check two: every name, place, and program — introduced or cut?","Check three: read aloud; your ear catches what your eye forgives."],"focus":["audience","clarity"]},
    {"id":"together-stu-early-03","level":"early","profession":"student","title":"Sixty seconds at the assembly","scenario":"You have one minute at the class assembly to announce the blood drive and get sign-ups. Everything you've practiced converges: lead with the point, know the audience, one concrete number, one clear ask. And it has to sound like you, spoken, not read.","task":"Write the 4-5 sentence spoken announcement.","tips":["First sentence: what's happening and the one thing you want from them.","One statistic that lands, one sentence of why it matters here.","End on the exact action: where, when, how long it takes."],"focus":["structure","impact"],"placeholder":"Two weeks from Friday, the gym becomes a blood drive — and we need 60 sign-ups."},
    {"id":"together-stu-early-04","level":"early","profession":"student","title":"Three answers, one story","scenario":"The scholarship application has three short-answer questions: your goals, your service, a challenge you overcame. You drafted them on different days and they read like three different people wrote them. Strong applications make the three answers face the same direction.","task":"Write the one-sentence through-line, then one line on how each answer would echo it.","tips":["Find the single thread already present in all three drafts.","Each answer can land on the thread in its last sentence.","Consistency reads as self-knowledge — the thing they're funding."],"focus":["structure","audience"]},
    {"id":"together-stu-early-05","level":"early","profession":"student","title":"The application email, end to end","scenario":"You're emailing your resume to the garden center that posted a summer job. Subject line through sign-off, every piece works or leaks: the subject gets it opened, the first line says why you're writing, the middle proves fit in two sentences, the close makes replying easy.","task":"Write the complete email: subject line plus a 4-sentence body.","tips":["Subject: position and your name — searchable, specific.","Sentence one: the job you want and where you saw it.","Close with availability and the attached resume named."],"focus":["structure","audience"],"placeholder":"Subject: Summer crew application — Sam Rivera"},
    {"id":"together-stu-early-06","level":"early","profession":"student","title":"The handoff that survives you","scenario":"You're writing the transition doc for next year's club president. It needs everything you've practiced at once: grouped structure (first week / monthly / emergencies), precise details (real names, real dates, real logins location), concision, and a reader who can't ask you follow-ups.","task":"Write the doc's opening: a 2-sentence orientation plus its 3 section headers.","tips":["Open by telling them what this doc is and how to use it.","Sections by when-they'll-need-it, not by when-you-remembered-it.","Every instruction passes the stranger test: no 'the usual,' no 'ask around.'"],"focus":["structure","audience"]},
    {"id":"together-stu-early-07","level":"early","profession":"student","title":"Choose the channel, then the words","scenario":"You want to ask your English teacher to mentor your independent-study proposal — a real commitment for her. Email is easy to send and easy to decline; in person is harder to schedule and harder to refuse. The channel IS part of the message.","task":"Pick the channel, justify it in one sentence, and write the 2-3 sentence opening ask.","tips":["Big asks deserve synchronous channels; logistics can follow by email.","In person: lead with the ask anyway — don't ambush her with small talk first.","Prepare the fallback: 'want to think about it?' offered before she has to ask for it."],"focus":["audience","impact"]},
    {"id":"together-stu-early-08","level":"early","profession":"student","title":"Editing your friend's essay like a reader","scenario":"Your friend asked you to review their college essay tonight. The lazy review — 'it's really good!' — helps nobody. The useful review reports your actual reading experience: where you were confused, where you skimmed, where you felt something, what you remembered after.","task":"Write the 3-4 sentence feedback note using reader-experience observations, ending with the one fix that matters most.","tips":["Report experiences, not verdicts: 'I lost the thread here' beats 'this part is bad.'","Say what you remembered an hour later — that's the essay's real headline.","One priority fix, named; five fixes is a to-do list nobody starts."],"focus":["audience","clarity"],"placeholder":"What stuck with me an hour later was the scene with your dad's toolbox —"},
    {"id":"together-stu-early-09","level":"early","profession":"student","title":"Text or email the counselor?","scenario":"You need your counselor to fix a transcript error before Friday's application deadline. The school portal has messaging; she also gives students her email; there's also just showing up at her office. Urgency, record-keeping, and her workflow all point somewhere.","task":"Choose the channel, defend it in one sentence, and write the message (2-3 sentences).","tips":["Deadline problems need channels with receipts — and a same-day nudge path.","Whatever channel: the error, the deadline, and the ask in the first two sentences.","Belt and suspenders is legitimate: message now, office visit at lunch."],"focus":["audience","structure"]},
    {"id":"together-stu-early-10","level":"early","profession":"student","title":"The complete extension request","scenario":"Everything at once: your research paper is due Monday; a genuine family emergency ate your weekend. The request needs the BLUF opening, your teacher's perspective (fairness to other students), precise dates, and the hard part said plainly — the work isn't done.","task":"Write the full 4-5 sentence email.","tips":["Ask plus proposed new deadline in sentence one.","Acknowledge the fairness problem and accept the standard penalty if that's policy.","Precise state of the work: what percent exists, what remains.","One sentence of circumstance — informative, not performative."],"focus":["structure","clarity"],"placeholder":"Could I have until Wednesday for the research paper? Here's the honest picture:"},
    {"id":"together-stu-early-11","level":"early","profession":"student","title":"One minute, whole toolkit","scenario":"Club fair, final period, your one-minute pitch to a cluster of freshmen. Point first (what the club does for them), audience-native language (no insider terms), one precise proof (what the club did last year), and a single tiny next step.","task":"Write the 4-sentence spoken pitch hitting all four beats.","tips":["Beat one: what they get, in their terms, sentence one.","Beat three needs a real number: members, events, the trip you took.","The next step should take ten seconds: name on this sheet."],"focus":["audience","impact"]},
    {"id":"together-stu-early-12","level":"early","profession":"student","title":"The follow-up to the college rep","scenario":"You talked to a college rep at the fall fair and she said 'email me about the marine bio program.' Three weeks later, you finally are. The email needs to reintroduce you precisely, ask one specific question, and be effortless to answer — a formal register you rarely use, held for four sentences.","task":"Write the 4-sentence email.","tips":["Reintroduce with a hook she might remember: the fair, your question about the research vessel.","ONE question, specific enough that her answer is short.","Formal but human — no thesaurus voice.","Proofread twice; this register punishes typos."],"focus":["audience","precision"]},
    {"id":"together-stu-early-13","level":"early","profession":"student","title":"Same request, teacher and friend","scenario":"You need notes from the class you missed — from your teacher (who posts slides but not the discussion) and from your friend (who takes great notes). Same underlying need, two asks in two registers, each shaped by what that person can actually give.","task":"Write both messages: 2 sentences to the teacher, 1 line to the friend.","tips":["Teacher: specific gap you're filling, not 'what did I miss?'","Friend: casual, direct, with the trade implied or offered.","Neither should be the other one with the greeting swapped."],"focus":["audience","concision"],"placeholder":"To Ms. Chen: I've reviewed Tuesday's slides — could you point me to what the discussion added on"},
    {"id":"together-stu-early-14","level":"early","profession":"student","title":"The incident report at work","scenario":"A customer slipped on a wet floor at the smoothie shop during your shift — unhurt, but your manager needs a written account for the file. This is a register you've never written: factual, time-stamped, complete, zero speculation, zero covering. Just what a camera would say, signed by you.","task":"Write the 3-4 sentence incident account.","tips":["Times, places, actions — in order, no interpretation.","What you did in response belongs; what you fear about blame doesn't.","Precision protects everyone, including you: 'about 3:15' beats 'later on.'"],"focus":["precision","structure"],"placeholder":"At about 3:15pm, a customer slipped near the blender station, where"},
    {"id":"together-stu-early-15","level":"early","profession":"student","title":"From notes to news","scenario":"You covered the school board meeting for the student paper: 90 minutes, four agenda items, your notes in chronological order. The article can't be your notes retyped. News structure is a decision: the lede (what readers care about most), then support in descending importance.","task":"Write the lede sentence and name your next 2 paragraphs' topics in order.","tips":["The lede is the outcome that touches students — probably not agenda item one.","Inverted pyramid: each paragraph survivable as the last.","Chronology is how meetings happen, not how news reads."],"focus":["structure","audience"]},
    {"id":"together-stu-early-16","level":"early","profession":"student","title":"Spoken vs posted","scenario":"The talent show needs performers. You're writing two versions of the same call: a 15-second PA announcement (heard once, half-listened) and a hallway poster (read in 3 seconds, but re-readable). Ears and eyes need different writing.","task":"Write both: the 2-sentence PA script and the poster's 3 lines.","tips":["PA: repeat the one action twice — first and last words.","Poster: biggest line is the what-and-when; details shrink from there.","Neither carries everything; each carries what its medium can."],"focus":["audience","concision"]},
    {"id":"together-stu-early-17","level":"early","profession":"student","title":"Close the loop","scenario":"You ran today's club meeting with the agenda you practiced. Now the other half of the discipline: the follow-up message, same day, while it's warm — decisions made, actions owned, dates attached. Meetings without written follow-ups slowly un-happen.","task":"Write the 3-4 line follow-up message: one decision, two action items with names and dates, next meeting.","tips":["Post it the same day — the half-life of meeting memory is short.","Every action has a name and a date or it isn't an action.","Keep it scannable: one line per item, no prose."],"focus":["structure","concision"],"placeholder":"Recap from today: Decided — spring event is a trivia night, April 18."},
    {"id":"together-stu-early-18","level":"early","profession":"student","title":"The thank-you that closes the interview","scenario":"You interviewed at the vet clinic this morning. The thank-you email is a register exercise: warm but not gushing, specific but brief, professional from a seventeen-year-old without sounding like a lawyer wrote it. Three sentences, sent today.","task":"Write the 3-sentence email.","tips":["Thank once, reference one specific exchange from the conversation, restate availability.","The specific reference does the work — it proves you listened.","Send within 24 hours; timing is part of the message."],"focus":["audience","concision"]},
    {"id":"together-stu-early-19","level":"early","profession":"student","title":"The five-sentence case to the principal","scenario":"Your club needs the principal's sign-off to host a weekend tournament at school. One email, and she reads fast: SCQA shape, her stakes (liability, custodians, precedent) pre-answered, exact logistics, one clear yes/no ask. Everything you've practiced, in five sentences.","task":"Write the 5-sentence email.","tips":["Situation and ask within the first two sentences.","Answer her three objections before she forms them: supervision, cleanup, insurance.","End with the decision needed and the date you need it by."],"focus":["structure","audience"],"placeholder":"We'd like your approval to host the regional chess tournament in the cafeteria on Saturday, March 14."},
    {"id":"together-stu-early-20","level":"early","profession":"student","title":"The sixty-second opening","scenario":"Your group presents its semester project Friday, and you open. Sixty seconds to do four jobs: state the point (your finding), tell them why they should care (audience stake), map the next ten minutes (signposts), and hand off to the next speaker cleanly.","task":"Write the 4-5 sentence spoken opening.","tips":["Finding first — the presentation is the evidence for it, not the buildup to it.","One sentence connecting the finding to THIS audience.","Signpost by speaker: 'Priya shows the data, Marcus the costs, I'll close with the fix.'"],"focus":["structure","impact"]},
    {"id":"together-stu-early-21","level":"early","profession":"student","title":"Fixing the confusing email","scenario":"You emailed your project group yesterday and got three confused replies — your message mixed two topics, buried the deadline, and left 'someone should' hanging with no name. Today's follow-up has to fix all three faults and be shorter than the original.","task":"Write the 3-sentence corrected message.","tips":["One topic per message; the second topic gets its own thread.","Deadline in the first line, name attached to every task.","Don't explain the confusion at length — just be clear this time."],"focus":["clarity","concision"],"placeholder":"Clearer version: slides are due to the shared folder by Thursday 8pm."},
    {"id":"together-stu-early-22","level":"early","profession":"student","title":"The final read","scenario":"Personal statement, final pass, submitting tonight. Not a rewrite — a discipline: does the first sentence earn the second? Is every claim shown, not announced? Does anything exist only because cutting it hurt? Is the last line the one you'd want remembered?","task":"Write the 4-question checklist you'd run, as questions a reader would ask.","tips":["Each question should be answerable by pointing at the text.","The 'darling' question matters most: what survives only because you're attached?","Read the first and last sentences alone, as a pair — they should feel like the same essay."],"focus":["clarity","impact"]},
    {"id":"together-stu-early-23","level":"early","profession":"student","title":"The dues reminder to a friend","scenario":"You're the club treasurer, and your good friend is the last member who hasn't paid the $15 dues — three weeks late. DM, not public channel; friendly, not fake; clear, not squishy. The role and the friendship both have to survive the message.","task":"Write the 2-sentence DM.","tips":["Right channel: private, casual — the register of the friendship, the content of the role.","The ask is exact: amount, method, date.","No apology for doing your job; no coldness either."],"focus":["audience","clarity"],"placeholder":"Hey — treasurer hat on for a sec: your $15 dues are the last ones out."},
    {"id":"together-stu-early-24","level":"early","profession":"student","title":"The season recap for families","scenario":"The season's over and you're writing the recap email to players' families: results (11-3, first playoff berth in six years), thank-yous (the carpools, the snack rotation, the loudest parents in the league), and next season's first date. Warm, precise, skimmable — all three at once.","task":"Write the 4-sentence email body.","tips":["Lead with the season's headline number — families love a scoreboard.","Thank specifically: named efforts, not 'everyone who helped.'","End with the one date to put in calendars now."],"focus":["audience","structure"]},
    {"id":"together-stu-early-25","level":"early","profession":"student","title":"The one-page funding pitch","scenario":"The capstone: your club wants $500 from the student activities fund, and the committee accepts one-page written pitches. Everything converges — BLUF ask, committee's criteria (students served per dollar), line-item budget, the strongest objection pre-answered, and a closing line that makes yes easy.","task":"Write the pitch's core: 6-7 sentences covering ask, case, budget summary, objection, and close.","tips":["The ask and the headline benefit share sentence one.","Quantify the case in the committee's own metric.","Name the likely objection ('didn't this club get funds last year?') and answer it in one sentence.","Close with the smallest possible next step for the committee."],"focus":["structure","impact"],"placeholder":"We're requesting $500 to run three open-to-everyone game nights that reached 140 students last year."}
  ],
};
